{
  "name": "EduGrade AI - Yazılı Sınav Asistanı",
  "description": "Öğretmenler için el yazısı sınav kağıtlarını yapay zeka ile okuyan, puanlayan ve geri bildirim veren akıllı değerlendirme asistanı.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface Question {
  id: string;
  text: string;
  expectedAnswer: string;
  keywords: string[];
  maxScore: number;
}

export interface Exam {
  id: string;
  title: string;
  date: string;
  questions: Question[];
}

export interface GradingResult {
  questionId: string;
  extractedText: string;
  score: number;
  reason: string;
  feedback: string;
  confidence: number; // 0 to 1
}

export interface StudentSubmission {
  id: string;
  studentName: string;
  imageUrl: string;
  base64Data: string;
  status: 'pending' | 'processing' | 'graded' | 'reviewed';
  results: GradingResult[];
  totalScore: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Exam, GradingResult, StudentSubmission } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const gradeSubmission = async (
  exam: Exam,
  submission: StudentSubmission
): Promise<{ results: GradingResult[]; totalScore: number }> => {
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    Sen bir öğretmen asistanısın. Görevin, yüklenen el yazısı sınav kağıdını okumak, metni dijitalleştirmek ve sağlanan cevap anahtarına göre puanlamaktır.

    KURALLAR:
    1. El yazısını en doğru şekilde oku.
    2. Her bir soruyu cevap anahtarıyla karşılaştır. 
    3. Anlamsal benzerliğe odaklan; öğrenci aynı şeyi farklı kelimelerle söylemiş olabilir.
    4. Anahtar kelimelerin varlığını kontrol et ama sadece anahtar kelime sayısına göre puan verme, anlamı bütün olarak değerlendir.
    5. Her soru için bir puan (0 ile maxScore arası), puanlama gerekçesi (reason) ve öğrenciye geri bildirim (feedback) oluştur.
    6. Eğer el yazısı çok kötüyse ve emin değilsen 'confidence' değerini düşük tut.

    Dönüş formatı kesinlikle bir JSON listesi olmalıdır.
  `;

  const prompt = `
    Sınav Başlığı: ${exam.title}
    Sorular ve Cevap Anahtarı:
    ${exam.questions.map(q => `
      Soru ID: ${q.id}
      Soru: ${q.text}
      Beklenen Cevap: ${q.expectedAnswer}
      Anahtar Kelimeler: ${q.keywords.join(', ')}
      Maksimum Puan: ${q.maxScore}
    `).join('\n')}

    Lütfen bu kağıdı değerlendir ve her soru için şu şemaya uygun bir JSON döndür:
    [{ "questionId": "string", "extractedText": "string", "score": number, "reason": "string", "feedback": "string", "confidence": number }]
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: submission.base64Data,
            },
          },
        ],
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              questionId: { type: Type.STRING },
              extractedText: { type: Type.STRING },
              score: { type: Type.NUMBER },
              reason: { type: Type.STRING },
              feedback: { type: Type.STRING },
              confidence: { type: Type.NUMBER },
            },
            required: ["questionId", "extractedText", "score", "reason", "feedback", "confidence"],
          },
        },
      },
    });

    const results: GradingResult[] = JSON.parse(response.text || "[]");
    const totalScore = results.reduce((acc, curr) => acc + curr.score, 0);

    return { results, totalScore };
  } catch (error) {
    console.error("Gemini Grading Error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Exam, StudentSubmission, Question } from './types';
import Header from './components/Header';
import ExamSetup from './components/ExamSetup';
import UploadSection from './components/UploadSection';
import GradingDashboard from './components/GradingDashboard';
import GradingDetail from './components/GradingDetail';
import AnalyticsView from './components/AnalyticsView';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'setup' | 'upload' | 'dashboard' | 'detail' | 'analytics'>('setup');
  const [exam, setExam] = useState<Exam | null>(null);
  const [submissions, setSubmissions] = useState<StudentSubmission[]>([]);
  const [selectedSubmissionId, setSelectedSubmissionId] = useState<string | null>(null);

  // Persistence
  useEffect(() => {
    const savedExam = localStorage.getItem('edugrade_exam');
    const savedSubmissions = localStorage.getItem('edugrade_submissions');
    if (savedExam) setExam(JSON.parse(savedExam));
    if (savedSubmissions) setSubmissions(JSON.parse(savedSubmissions));
  }, []);

  const saveToLocal = (updatedExam: Exam | null, updatedSubmissions: StudentSubmission[]) => {
    if (updatedExam) localStorage.setItem('edugrade_exam', JSON.stringify(updatedExam));
    localStorage.setItem('edugrade_submissions', JSON.stringify(updatedSubmissions));
  };

  const handleExamSaved = (newExam: Exam) => {
    setExam(newExam);
    saveToLocal(newExam, submissions);
    setCurrentView('upload');
  };

  const handleUploadComplete = (newSubmissions: StudentSubmission[]) => {
    const updated = [...submissions, ...newSubmissions];
    setSubmissions(updated);
    saveToLocal(exam, updated);
    setCurrentView('dashboard');
  };

  const handleSubmissionUpdate = (updatedSub: StudentSubmission) => {
    const updated = submissions.map(s => s.id === updatedSub.id ? updatedSub : s);
    setSubmissions(updated);
    saveToLocal(exam, updated);
  };

  const renderView = () => {
    switch (currentView) {
      case 'setup':
        return <ExamSetup initialExam={exam} onSave={handleExamSaved} />;
      case 'upload':
        return <UploadSection onUpload={handleUploadComplete} exam={exam!} />;
      case 'dashboard':
        return (
          <GradingDashboard 
            submissions={submissions} 
            onSelect={(id) => { setSelectedSubmissionId(id); setCurrentView('detail'); }}
            onReset={() => { setSubmissions([]); saveToLocal(exam, []); }}
            onViewAnalytics={() => setCurrentView('analytics')}
          />
        );
      case 'detail':
        const sub = submissions.find(s => s.id === selectedSubmissionId);
        if (!sub) return null;
        return (
          <GradingDetail 
            submission={sub} 
            exam={exam!} 
            onBack={() => setCurrentView('dashboard')} 
            onUpdate={handleSubmissionUpdate}
          />
        );
      case 'analytics':
        return <AnalyticsView submissions={submissions} exam={exam!} onBack={() => setCurrentView('dashboard')} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header 
        currentView={currentView} 
        onNavigate={(view) => setCurrentView(view)} 
        isExamSet={!!exam}
      />
      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        {renderView()}
      </main>
    </div>
  );
};

export default App;

import React from 'react';

