  isExamSet: boolean;
}

const Header: React.FC<HeaderProps> = ({ currentView, onNavigate, isExamSet }) => {
  return (
    <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
      <div className="container mx-auto px-4 h-16 flex items-center justify-between max-w-5xl">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
            <span className="text-white font-bold">E</span>
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600">
            EduGrade AI
          </h1>
        </div>

        <nav className="flex gap-1">
          <button 
            onClick={() => onNavigate('setup')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
              currentView === 'setup' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-50'
            }`}
          >
            Sınav Hazırla
          </button>

          <button 
            onClick={() => onNavigate('upload')}
            disabled={!isExamSet}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
              currentView === 'upload' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-50'
            } disabled:opacity-50`}
          >
            Yükle
          </button>

          <button 
            onClick={() => onNavigate('dashboard')}
            disabled={!isExamSet}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
              currentView === 'dashboard' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-50'
            } disabled:opacity-50`}
          >
            Sonuçlar
          </button>
        </nav>
      </div>
    </header>
  );
};

export default Header;

import React, { useState } from 'react';
import { Exam, Question } from '../types';

interface ExamSetupProps {
  initialExam: Exam | null;
  onSave: (exam: Exam) => void;
}

const ExamSetup: React.FC<ExamSetupProps> = ({ initialExam, onSave }) => {
  const [title, setTitle] = useState(initialExam?.title || '');
  const [questions, setQuestions] = useState<Question[]>(initialExam?.questions || [
    { id: '1', text: '', expectedAnswer: '', keywords: [], maxScore: 10 }
  ]);

  const addQuestion = () => {
    setQuestions([...questions, { 
      id: Date.now().toString(), 
      text: '', 
      expectedAnswer: '', 
      keywords: [], 
      maxScore: 10 
    }]);
  };

  const removeQuestion = (id: string) => {
    setQuestions(questions.filter(q => q.id !== id));
  };

  const updateQuestion = (id: string, field: keyof Question, value: any) => {
    setQuestions(questions.map(q => q.id === id ? { ...q, [field]: value } : q));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim() || questions.length === 0) return;
    onSave({
      id: initialExam?.id || Date.now().toString(),
      title,
      date: new Date().toISOString(),
      questions
    });
  };

  return (
    <div className="animate-fade-in">
      <div className="mb-8">
        <h2 className="text-2xl font-bold text-slate-800">Sınav Yapılandırması</h2>
        <p className="text-slate-500">Öğrencilerin kağıtlarını okumadan önce soru ve cevap anahtarını belirleyin.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <label className="block text-sm font-semibold text-slate-700 mb-2">Sınav Başlığı</label>
          <input 
            type="text" 
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Örn: 10. Sınıf Biyoloji 1. Yazılı"
            className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            required
          />
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-semibold text-slate-800">Sorular</h3>
            <span className="text-sm text-slate-500">Toplam Puan: {questions.reduce((a, b) => a + b.maxScore, 0)}</span>
          </div>

          {questions.map((q, index) => (
            <div key={q.id} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm relative group">
              <button 
                type="button"
                onClick={() => removeQuestion(q.id)}
                className="absolute top-4 right-4 text-slate-300 hover:text-red-500 transition-colors"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
              </button>

              <div className="grid grid-cols-1 md:grid-cols-12 gap-4">
                <div className="md:col-span-1">
                  <span className="w-8 h-8 flex items-center justify-center bg-slate-100 rounded-full text-slate-600 font-bold text-sm">
                    {index + 1}
                  </span>
                </div>
                <div className="md:col-span-11 space-y-4">
                  <div>
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Soru Metni</label>
                    <textarea 
                      value={q.text}
                      onChange={(e) => updateQuestion(q.id, 'text', e.target.value)}
                      placeholder="Soruyu buraya yazın..."
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none min-h-[60px]"
                      required
                    />
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Beklenen Doğru Cevap</label>
                      <textarea 
                        value={q.expectedAnswer}
                        onChange={(e) => updateQuestion(q.id, 'expectedAnswer', e.target.value)}
                        placeholder="İdeal cevabı yazın..."
                        className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none min-h-[60px]"
                        required
                      />
                    </div>
                    <div>
                      <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Anahtar Kelimeler (Virgülle ayırın)</label>
                      <input 
                        type="text"
                        value={q.keywords.join(', ')}
                        onChange={(e) => updateQuestion(q.id, 'keywords', e.target.value.split(',').map(s => s.trim()))}
                        placeholder="glikoz, ışık, yaprak..."
                        className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                      />
                      <div className="mt-2 flex flex-wrap gap-1">
                        {q.keywords.filter(k => k).map((k, i) => (
                          <span key={i} className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] rounded border border-indigo-100">{k}</span>
                        ))}
                      </div>
                    </div>
                  </div>
                  <div className="w-32">
                    <label className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1 block">Puan Değeri</label>
                    <input 
                      type="number"
                      value={q.maxScore}
                      onChange={(e) => updateQuestion(q.id, 'maxScore', parseInt(e.target.value))}
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="flex flex-col sm:flex-row gap-4 pt-4">
          <button 
            type="button"
            onClick={addQuestion}
            className="flex-1 py-3 border-2 border-dashed border-slate-200 rounded-xl text-slate-500 hover:border-indigo-300 hover:text-indigo-600 transition-all font-medium flex items-center justify-center gap-2"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
            Yeni Soru Ekle
          </button>

          <button 
            type="submit"
            className="flex-1 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-all font-bold shadow-lg shadow-indigo-100"
          >
            Sınavı Kaydet ve İlerle
          </button>
        </div>
      </form>
    </div>
  );
};

export default ExamSetup;

import React, { useState } from 'react';
import { Exam, StudentSubmission } from '../types';
import { gradeSubmission } from '../services/geminiService';

interface UploadSectionProps {
  exam: Exam;
  onUpload: (submissions: StudentSubmission[]) => void;
}

const UploadSection: React.FC<UploadSectionProps> = ({ exam, onUpload }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsProcessing(true);
    setError(null);
    const newSubmissions: StudentSubmission[] = [];

    try {
      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        setUploadProgress(Math.round(((i) / files.length) * 100));

        const base64 = await fileToBase64(file);

        // Initial object
        const sub: StudentSubmission = {
          id: Date.now().toString() + i,
          studentName: file.name.split('.')[0] || `Öğrenci ${i + 1}`,
          imageUrl: URL.createObjectURL(file),
          base64Data: base64.split(',')[1],
          status: 'processing',
          results: [],
          totalScore: 0
        };

        try {
          // Trigger AI Grading
          const { results, totalScore } = await gradeSubmission(exam, sub);
          sub.results = results;
          sub.totalScore = totalScore;
          sub.status = 'graded';
        } catch (err) {
          console.error("Grading failed for file", file.name, err);
          sub.status = 'pending'; // Fallback to manual if AI fails
        }

        newSubmissions.push(sub);
      }

      onUpload(newSubmissions);
    } catch (err) {
      setError("Bir hata oluştu. Lütfen tekrar deneyin.");
    } finally {
      setIsProcessing(false);
      setUploadProgress(0);
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  return (
    <div className="max-w-2xl mx-auto py-12 text-center animate-fade-in">
      <div className="mb-8">
        <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center mx-auto mb-4">
          <svg className="w-10 h-10 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
        </div>
        <h2 className="text-2xl font-bold text-slate-800">Sınav Kağıtlarını Yükleyin</h2>
        <p className="text-slate-500 mt-2">Öğrencilerin kağıtlarını fotoğraf veya PDF olarak yükleyin. AI otomatik olarak okumaya başlayacaktır.</p>
      </div>

      <div className={`relative border-2 border-dashed rounded-3xl p-12 transition-all ${isProcessing ? 'border-indigo-300 bg-indigo-50/50' : 'border-slate-200 hover:border-indigo-400 bg-white'}`}>
        {!isProcessing ? (
          <>
            <input 
              type="file" 
              multiple 
              accept="image/*,application/pdf"
              onChange={handleFileChange}
              className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
            />
            <div className="space-y-4">
              <button className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all inline-flex items-center gap-2">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
                Dosyaları Seç
              </button>
              <p className="text-sm text-slate-400">Veya dosyaları buraya sürükleyin</p>
            </div>
          </>
        ) : (
          <div className="space-y-6">
            <div className="flex flex-col items-center">
              <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
              <p className="text-indigo-700 font-semibold text-lg">Yapay Zeka Okuyor...</p>
              <p className="text-slate-500 text-sm mt-1">El yazıları analiz ediliyor ve puanlanıyor.</p>
            </div>
            <div className="w-full bg-slate-200 rounded-full h-2">
              <div 
                className="bg-indigo-600 h-2 rounded-full transition-all duration-300" 
                style={{ width: `${uploadProgress}%` }}
              ></div>
            </div>
            <div className="flex justify-between text-xs font-bold text-slate-500 uppercase">
              <span>İlerleme</span>
              <span>%{uploadProgress}</span>
            </div>
          </div>
        )}
      </div>

      {error && (
        <div className="mt-4 p-4 bg-red-50 text-red-700 rounded-xl border border-red-100 text-sm">
          {error}
        </div>
      )}

      <div className="mt-12 grid grid-cols-1 md:grid-cols-3 gap-6 text-left">
        <div className="p-4 bg-white rounded-xl border border-slate-100">
          <div className="text-indigo-600 mb-2 font-bold">1. OCR</div>
          <p className="text-xs text-slate-500">Gelişmiş el yazısı tanıma teknolojisi ile metinler dijitalleştirilir.</p>
        </div>
        <div className="p-4 bg-white rounded-xl border border-slate-100">
          <div className="text-indigo-600 mb-2 font-bold">2. Anlam Analizi</div>
          <p className="text-xs text-slate-500">Öğrencinin cevabı anahtar kelime ve anlam bakımından değerlendirilir.</p>
        </div>
        <div className="p-4 bg-white rounded-xl border border-slate-100">
          <div className="text-indigo-600 mb-2 font-bold">3. Puanlama</div>
          <p className="text-xs text-slate-500">Belirlediğiniz rubriğe göre puan önerisi ve gerekçesi sunulur.</p>
        </div>
      </div>
    </div>
  );
};

export default UploadSection;

import React, { useState } from 'react';
import { StudentSubmission, Exam, GradingResult } from '../types';

interface GradingDetailProps {
  submission: StudentSubmission;
  exam: Exam;
  onBack: () => void;
  onUpdate: (submission: StudentSubmission) => void;
}

const GradingDetail: React.FC<GradingDetailProps> = ({ submission, exam, onBack, onUpdate }) => {
  const [editedSubmission, setEditedSubmission] = useState(submission);

  const handleScoreChange = (qId: string, newScore: number) => {
    const updatedResults = editedSubmission.results.map(r => 
      r.questionId === qId ? { ...r, score: newScore } : r
    );
    const total = updatedResults.reduce((acc, curr) => acc + curr.score, 0);
    setEditedSubmission({ 
      ...editedSubmission, 
      results: updatedResults, 
      totalScore: total,
      status: 'reviewed'
    });
  };

  const handleSave = () => {
    onUpdate(editedSubmission);
    onBack();
  };

  return (
    <div className="animate-fade-in pb-12">
      <div className="flex items-center justify-between mb-8">
        <button 
          onClick={onBack}
          className="flex items-center gap-2 text-slate-500 hover:text-indigo-600 transition-colors"
        >
