      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="text-sm font-bold text-slate-400 uppercase mb-1">En Başarılı Soru</div>
          {chartData.length > 0 && (
            <>
              <div className="text-2xl font-bold text-emerald-600">
                {chartData.reduce((prev, curr) => prev.başarı > curr.başarı ? prev : curr).name}
              </div>
              <div className="text-sm text-slate-500 mt-1">%{chartData.reduce((prev, curr) => prev.başarı > curr.başarı ? prev : curr).başarı} ortalama başarı</div>
            </>
          )}
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="text-sm font-bold text-slate-400 uppercase mb-1">En Çok Zorlanılan Soru</div>
          {chartData.length > 0 && (
            <>
              <div className="text-2xl font-bold text-rose-600">
                {chartData.reduce((prev, curr) => prev.başarı < curr.başarı ? prev : curr).name}
              </div>
              <div className="text-sm text-slate-500 mt-1">%{chartData.reduce((prev, curr) => prev.başarı < curr.başarı ? prev : curr).başarı} ortalama başarı</div>
            </>
          )}
        </div>
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="text-sm font-bold text-slate-400 uppercase mb-1">Puan Dağılımı</div>
          <div className="text-2xl font-bold text-slate-700">Homojen</div>
          <div className="text-sm text-slate-500 mt-1">Standart sapma: Düşük</div>
        </div>
      </div>

      <div className="bg-white p-8 rounded-2xl border border-slate-200 shadow-sm">
        <h3 className="text-lg font-bold text-slate-800 mb-6 text-center">Soruların Başarı Oranları (%)</h3>
        <div className="h-[400px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} dy={10} />
              <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} unit="%" />
