              <Bar dataKey="başarı" radius={[6, 6, 0, 0]} barSize={40}>
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.başarı > 70 ? '#10b981' : entry.başarı > 40 ? '#6366f1' : '#f43f5e'} />
                ))}
