import React, { useState, useEffect } from 'react';
import { Exam, StudentSubmission, Question } from './types';
import Header from './components/Header';
import ExamSetup from './components/ExamSetup';
import UploadSection from './components/UploadSection';
import GradingDashboard from './components/GradingDashboard';
import GradingDetail from './components/GradingDetail';
import AnalyticsView from './components/AnalyticsView';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'setup' | 'upload' | 'dashboard' | 'detail' | 'analytics'>('setup');
  const [exam, setExam] = useState<Exam | null>(null);
  const [submissions, setSubmissions] = useState<StudentSubmission[]>([]);
  const [selectedSubmissionId, setSelectedSubmissionId] = useState<string | null>(null);

  // Persistence
  useEffect(() => {
    const savedExam = localStorage.getItem('edugrade_exam');
    const savedSubmissions = localStorage.getItem('edugrade_submissions');
    if (savedExam) setExam(JSON.parse(savedExam));
    if (savedSubmissions) setSubmissions(JSON.parse(savedSubmissions));
  }, []);

  const saveToLocal = (updatedExam: Exam | null, updatedSubmissions: StudentSubmission[]) => {
    if (updatedExam) localStorage.setItem('edugrade_exam', JSON.stringify(updatedExam));
    localStorage.setItem('edugrade_submissions', JSON.stringify(updatedSubmissions));
  };

  const handleExamSaved = (newExam: Exam) => {
    setExam(newExam);
    saveToLocal(newExam, submissions);
    setCurrentView('upload');
  };

  const handleUploadComplete = (newSubmissions: StudentSubmission[]) => {
    const updated = [...submissions, ...newSubmissions];
    setSubmissions(updated);
    saveToLocal(exam, updated);
    setCurrentView('dashboard');
  };

  const handleSubmissionUpdate = (updatedSub: StudentSubmission) => {
    const updated = submissions.map(s => s.id === updatedSub.id ? updatedSub : s);
    setSubmissions(updated);
    saveToLocal(exam, updated);
  };

  const renderView = () => {
    switch (currentView) {
      case 'setup':
        return <ExamSetup initialExam={exam} onSave={handleExamSaved} />;
      case 'upload':
        return <UploadSection onUpload={handleUploadComplete} exam={exam!} />;
      case 'dashboard':
        return (
          <GradingDashboard 
            submissions={submissions} 
            onSelect={(id) => { setSelectedSubmissionId(id); setCurrentView('detail'); }}
            onReset={() => { if(confirm('Tüm sonuçlar silinecek. Emin misiniz?')) { setSubmissions([]); saveToLocal(exam, []); } }}
            onViewAnalytics={() => setCurrentView('analytics')}
          />
        );
      case 'detail':
        const sub = submissions.find(s => s.id === selectedSubmissionId);
        if (!sub) return null;
        return (
          <GradingDetail 
            submission={sub} 
            exam={exam!} 
            onBack={() => setCurrentView('dashboard')} 
            onUpdate={handleSubmissionUpdate}
          />
        );
      case 'analytics':
        return <AnalyticsView submissions={submissions} exam={exam!} onBack={() => setCurrentView('dashboard')} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col">
      <Header 
        currentView={currentView} 
        onNavigate={(view) => setCurrentView(view)} 
        isExamSet={!!exam}
      />
      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        {renderView()}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Exam, Question } from '../types';

interface ExamSetupProps {
  initialExam: Exam | null;
  onSave: (exam: Exam) => void;
}

const ExamSetup: React.FC<ExamSetupProps> = ({ initialExam, onSave }) => {
  const [title, setTitle] = useState(initialExam?.title || '');
  const [questions, setQuestions] = useState<Question[]>(initialExam?.questions || [
    { id: '1', text: '', expectedAnswer: '', keywords: [], maxScore: 10 }
  ]);

  const addQuestion = () => {
    setQuestions([...questions, { 
      id: Date.now().toString(), 
      text: '', 
      expectedAnswer: '', 
      keywords: [], 
      maxScore: 10 
    }]);
  };

  const removeQuestion = (id: string) => {
    setQuestions(questions.filter(q => q.id !== id));
  };

  const updateQuestion = (id: string, field: keyof Question, value: any) => {
    setQuestions(questions.map(q => q.id === id ? { ...q, [field]: value } : q));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim() || questions.length === 0) return;
    onSave({
      id: initialExam?.id || Date.now().toString(),
      title,
      date: new Date().toISOString(),
      questions
    });
  };

  return (
    <div className="animate-fade-in">
      <div className="mb-8">
        <h2 className="text-2xl font-bold text-white">Sınav Yapılandırması</h2>
        <p className="text-slate-400">Öğrencilerin kağıtlarını okumadan önce soru ve cevap anahtarını belirleyin.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-xl">
          <label className="block text-sm font-semibold text-indigo-950 mb-2 uppercase tracking-wide">Sınav Başlığı</label>
          <input 
            type="text" 
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Örn: 10. Sınıf Biyoloji 1. Yazılı"
            className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-600 outline-none transition-all text-indigo-950 font-medium"
            required
          />
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-semibold text-white">Sorular</h3>
            <span className="text-sm text-indigo-300 bg-indigo-900/50 px-3 py-1 rounded-full border border-indigo-800">Toplam Puan: {questions.reduce((a, b) => a + b.maxScore, 0)}</span>
          </div>

          {questions.map((q, index) => (
            <div key={q.id} className="bg-white p-6 rounded-xl border border-slate-200 shadow-lg relative group">
              <button 
                type="button"
                onClick={() => removeQuestion(q.id)}
                className="absolute top-4 right-4 text-slate-400 hover:text-red-500 transition-colors p-2 hover:bg-red-50 rounded-lg"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
              </button>

              <div className="grid grid-cols-1 md:grid-cols-12 gap-4">
                <div className="md:col-span-1">
                  <span className="w-8 h-8 flex items-center justify-center bg-indigo-100 rounded-full text-indigo-950 font-bold text-sm">
                    {index + 1}
                  </span>
                </div>
                <div className="md:col-span-11 space-y-4 text-indigo-950">
                  <div>
                    <label className="text-xs font-bold text-indigo-900 uppercase tracking-wider mb-1 block">Soru Metni</label>
                    <textarea 
                      value={q.text}
                      onChange={(e) => updateQuestion(q.id, 'text', e.target.value)}
