                        required
                      />
                    </div>
                    <div>
                      <label className="text-xs font-bold text-indigo-900 uppercase tracking-wider mb-1 block">Anahtar Kelimeler (Virgülle ayırın)</label>
                      <input 
                        type="text"
                        value={q.keywords.join(', ')}
                        onChange={(e) => updateQuestion(q.id, 'keywords', e.target.value.split(',').map(s => s.trim()))}
                        placeholder="glikoz, ışık, yaprak..."
                        className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-600 outline-none text-indigo-950"
                      />
