          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
            Yeni Soru Ekle
          </button>

          <button 
            type="submit"
            className="flex-1 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-all font-bold shadow-lg shadow-indigo-900/40"
          >
            Sınavı Kaydet ve İlerle
          </button>
        </div>
      </form>
    </div>
  );
};

