  onBack: () => void;
}

const AnalyticsView: React.FC<AnalyticsViewProps> = ({ submissions, exam, onBack }) => {
  const chartData = useMemo(() => {
    return exam.questions.map((q, idx) => {
      const scores = submissions.map(s => {
        const res = s.results.find(r => r.questionId === q.id);
        return res ? (res.score / q.maxScore) * 100 : 0;
      });
      const avg = scores.reduce((a, b) => a + b, 0) / (scores.length || 1);
      return {
        name: `Soru ${idx + 1}`,
        başarı: Math.round(avg),
        puan: q.maxScore
      };
    });
  }, [submissions, exam]);

  const bestQuestion = useMemo(() => chartData.length > 0 ? chartData.reduce((prev, curr) => prev.başarı > curr.başarı ? prev : curr) : null, [chartData]);
  const worstQuestion = useMemo(() => chartData.length > 0 ? chartData.reduce((prev, curr) => prev.başarı < curr.başarı ? prev : curr) : null, [chartData]);

  return (
