export const gradeSubmission = async (
  exam: Exam,
  submission: StudentSubmission
): Promise<{ results: GradingResult[]; totalScore: number }> => {
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    Sen profesyonel bir öğretmen asistanısın. Görevin, bir yazılı sınav kağıdını analiz etmek ve puanlamaktır.

    KURALLAR:
    1. El yazısını en yüksek doğrulukla dijital metne çevir (OCR).
    2. Öğrencinin yanıtını sağlanan "İdeal Doğru Cevap" ve "Anahtar Kelimeler" ile karşılaştır.
    3. PUANLAMA MANTIĞI: Kelime kelimesine aynılık bekleme. Anlamsal doğruluğu, kavram kullanımını ve mantık silsilesini değerlendir.
    4. Her soru için 0 ile maxScore arasında bir puan ver.
    5. 'reason' alanında neden bu puanı verdiğini pedagojik bir dille açıkla.
    6. 'feedback' alanında öğrenciye neyi eksik bıraktığını veya nasıl geliştirebileceğini söyle.

    Kesinlikle JSON formatında yanıt ver.
  `;

  const prompt = `
    SINAV BİLGİLERİ:
    Sınıf/Şube: ${exam.classSection}
    Ders: ${exam.courseName}
    Sınav: ${exam.examName}

    SORU VE CEVAP ANAHTARI:
    ${exam.questions.map(q => `
      Soru ID: ${q.id}
      Soru: ${q.text}
      İdeal Yanıt: ${q.expectedAnswer}
      Anahtar Kelimeler: ${q.keywords.join(', ')}
      Maksimum Puan: ${q.maxScore}
    `).join('\n')}

    Bu öğrenci kağıdını değerlendir.
    Dönüş Şeması:
    [{ "questionId": "string", "extractedText": "string", "score": number, "reason": "string", "feedback": "string", "confidence": number }]
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: submission.base64Data,
            },
          },
        ],
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              questionId: { type: Type.STRING },
              extractedText: { type: Type.STRING },
              score: { type: Type.NUMBER },
              reason: { type: Type.STRING },
              feedback: { type: Type.STRING },
              confidence: { type: Type.NUMBER },
            },
            required: ["questionId", "extractedText", "score", "reason", "feedback", "confidence"],
          },
        },
      },
    });

    const results: GradingResult[] = JSON.parse(response.text || "[]");
    const totalScore = results.reduce((acc, curr) => acc + curr.score, 0);

    return { results, totalScore };
  } catch (error) {
    console.error("Gemini Grading Error:", error);
    throw error;
  }
};

