import { GoogleGenAI, Type } from "@google/genai";
import { Exam, GradingResult, StudentSubmission } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const gradeSubmission = async (
  exam: Exam,
  submission: StudentSubmission
): Promise<{ results: GradingResult[]; totalScore: number }> => {
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    Sen uzman bir kıdemli öğretmensin ve asistan olarak görev yapıyorsun. Görevin, el yazısı sınav kağıtlarını titizlikle analiz etmek, puanlamak ve öğrencilere yol gösterici geri bildirimler sağlamaktır.

    ANALİZ VE PUANLAMA KURALLARI:
    1. OCR: El yazısını en yüksek doğrulukla dijital metne çevir. Okunmayan yerleri "[okunamadı]" olarak işaretle.
    2. ANLAMSAL DEĞERLENDİRME: Öğrencinin yanıtını sadece kelime eşleşmesi olarak değil, "İdeal Yanıt" ile anlamsal derinlik açısından kıyasla.
    3. PUANLAMA: Puanı maxScore üzerinden adilce dağıt. Tam doğru yanıtlar tam puan alır; kısmi doğrular, mantık silsilesi korunmuşsa puan kazanır.
    4. REASON (GEREKÇE): Öğretmen için yazılır. Puanın neden kırıldığını veya neden tam verildiğini teknik/pedagojik olarak açıkla.

    GERİ BİLDİRİM (FEEDBACK) KURALLARI:
    Öğrenciye doğrudan hitap et ve şu unsurları mutlaka dahil et:
    - EKSİK KAVRAMLAR: "Kritik Kavramlar" listesindeki hangi kelimelerin veya fikirlerin yanıtta yer almadığını net bir şekilde belirt.
    - KAVRAM YANILGILARI: Eğer öğrenci bir şeyi yanlış biliyorsa (örn: fotosentezi solunumla karıştırmak), bu hatayı nazikçe düzelt.
    - GELİŞİM ÖNERİSİ: "Bu soruyu tam cevaplamak için şu konuya tekrar bakmalısın" gibi somut bir öneri sun.
    - AÇIKLAYICI TON: Sadece "Eksik" deme; "Cevabında 'ışık enerjisi' kavramından bahsetmemişsin, bu da besin üretim sürecinin temelidir" gibi detaylandır.

    Kesinlikle JSON formatında yanıt ver.
  `;

  const prompt = `
    Aşağıdaki sınav detaylarına göre öğrenci kağıdını değerlendir:

    SINAV KİMLİĞİ:
    Sınıf/Şube: ${exam.classSection}
    Ders: ${exam.courseName}
    Sınav: ${exam.examName}

    DEĞERLENDİRİLECEK SORULAR VE RUBRİK:
    ${exam.questions.map(q => `
      - SORU ID: ${q.id}
      - SORU: ${q.text}
      - BEKLENEN İDEAL YANIT: ${q.expectedAnswer}
      - MUTLAKA GEÇMESİ GEREKEN KAVRAMLAR (ANAHTAR KELİMELER): ${q.keywords.join(', ')}
      - MAKSİMUM PUAN: ${q.maxScore}
    `).join('\n')}

    ANALİZ EDİLECEK ÖĞRENCİ VERİSİ:
    Öğrenci Adı: ${submission.studentName}
    (Kağıt görüntüsü ektedir.)

    Dönüş Şeması (JSON Array):
    [{ 
      "questionId": "string", 
      "extractedText": "string", 
      "score": number, 
      "reason": "Öğretmen için puanlama açıklaması", 
      "feedback": "Öğrenci için detaylı, kavram odaklı ve eğitici geri bildirim", 
      "confidence": number 
    }]
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: submission.base64Data,
            },
          },
        ],
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              questionId: { type: Type.STRING },
              extractedText: { type: Type.STRING },
              score: { type: Type.NUMBER },
              reason: { type: Type.STRING },
              feedback: { type: Type.STRING },
              confidence: { type: Type.NUMBER },
            },
            required: ["questionId", "extractedText", "score", "reason", "feedback", "confidence"],
          },
        },
      },
    });

    const results: GradingResult[] = JSON.parse(response.text || "[]");
    const totalScore = results.reduce((acc, curr) => acc + curr.score, 0);

    return { results, totalScore };
  } catch (error) {
    console.error("Gemini Grading Error:", error);
    throw error;
  }
};

