            const result = editedSubmission.results.find(r => r.questionId === q.id);
            if (!result) return null;
            const isApproved = approvedIds.has(q.id);
            const isEditing = editingId === q.id;

            return (
              <div key={q.id} className={`bg-white rounded-[3.5rem] border-2 shadow-2xl overflow-hidden text-indigo-950 transition-all group relative ${isApproved ? 'border-emerald-200' : 'border-slate-100'}`}>
                <div className={`absolute top-0 left-0 w-3 h-full transition-colors ${isApproved ? 'bg-emerald-500' : 'bg-slate-100 group-hover:bg-indigo-600'}`}></div>

                {/* Header: Soru No ve Dinamik Puan */}
                <div className={`p-10 border-b-2 flex flex-col sm:flex-row items-center justify-between gap-8 transition-colors ${isApproved ? 'bg-emerald-50/50 border-emerald-100' : 'bg-indigo-50/20 border-indigo-50'}`}>
                  <div className="flex items-center gap-6">
                    <span className={`w-16 h-16 text-white rounded-[1.5rem] flex items-center justify-center text-2xl font-black shadow-2xl ring-12 ring-white transition-colors ${isApproved ? 'bg-emerald-600' : 'bg-indigo-950'}`}>
                      {idx + 1}
                    </span>
                    <div>
                       <h4 className="font-black text-xs uppercase tracking-[0.4em] text-indigo-950 mb-1">ANALİZ RAPORU</h4>
                       <div className="flex items-center gap-2">
                          <span className={`px-3 py-1 bg-white border rounded-lg text-[10px] font-black uppercase tracking-widest transition-colors ${isApproved ? 'border-emerald-200 text-emerald-600' : 'border-indigo-100 text-indigo-500'}`}>
                            {isApproved ? 'ONAYLANDI' : `GÜVEN SKORU: %${Math.round(result.confidence * 100)}`}
                          </span>
                       </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-6 bg-white p-6 rounded-[2rem] shadow-2xl border-2 border-indigo-50">
                    <div className="flex flex-col items-center">
                       <span className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.3em] mb-2">PUANLAMA</span>
                       <div className="flex items-center gap-4">
                          <input 
                            type="number" 
                            max={q.maxScore}
                            min={0}
                            value={result.score}
                            readOnly={!isEditing}
                            onChange={(e) => handleScoreChange(q.id, parseInt(e.target.value) || 0)}
                            className={`w-32 px-4 py-4 border-4 rounded-[1.25rem] text-center font-black text-5xl outline-none transition-all shadow-inner ${isEditing ? 'bg-white border-indigo-600 text-indigo-900 ring-8 ring-indigo-50' : 'bg-indigo-50/30 border-transparent text-indigo-900'}`}
                          />
                          <span className="text-indigo-200 font-black text-4xl">/ {q.maxScore}</span>
                       </div>
                    </div>

                    <div className="flex flex-col gap-3 ml-4">
                      {!isApproved && !isEditing ? (
                        <>
                          <button 
                            onClick={() => approveQuestion(q.id)}
                            className="px-6 py-2.5 bg-emerald-600 text-white rounded-xl font-black text-[11px] tracking-widest uppercase hover:bg-emerald-500 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                          >
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
                            ONAYLA
                          </button>
                          <button 
                            onClick={() => editQuestion(q.id)}
                            className="px-6 py-2.5 bg-amber-500 text-white rounded-xl font-black text-[11px] tracking-widest uppercase hover:bg-amber-400 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                          >
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                            DÜZELT
                          </button>
                        </>
                      ) : isEditing ? (
                        <button 
                          onClick={() => approveQuestion(q.id)}
                          className="px-6 py-5 bg-indigo-600 text-white rounded-xl font-black text-[11px] tracking-widest uppercase hover:bg-indigo-500 transition-all shadow-xl active:scale-95"
                        >
                          BİTTİ
                        </button>
                      ) : (
                        <button 
                          onClick={() => editQuestion(q.id)}
                          className="px-6 py-2.5 border-2 border-emerald-600 text-emerald-600 rounded-xl font-black text-[11px] tracking-widest uppercase hover:bg-emerald-50 transition-all active:scale-95"
                        >
                          DÜZENLE
                        </button>
                      )}
                    </div>
                  </div>
                </div>

                <div className="p-10 space-y-12">
                  {/* Soru İçeriği */}
                  <div className="bg-slate-950 text-slate-100 p-8 rounded-[2rem] shadow-2xl relative overflow-hidden">
