                     </div>
                     <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] mb-4 block">RESMİ SINAV SORUSU</span>
                     <p className="text-lg font-bold leading-relaxed pr-10">{q.text}</p>
