                      <p className="text-indigo-950 text-lg leading-relaxed font-black italic border-l-8 border-indigo-200 pl-6 mt-4">
                        "{result.extractedText || "Metin çıkarılamadı..."}"
                      </p>
                    </div>
                    <div className="bg-emerald-50 p-8 rounded-[2.5rem] border-2 border-emerald-100 relative transition-all hover:bg-white hover:shadow-xl">
                      <div className="absolute -top-4 left-8 px-5 py-2 bg-white border-2 border-emerald-200 rounded-2xl text-[10px] font-black text-emerald-500 uppercase tracking-[0.3em] shadow-sm">İDEAL REFERANS</div>
                      <p className="text-emerald-950 text-lg leading-relaxed font-bold border-l-8 border-emerald-200 pl-6 mt-4">
