                  </div>

                  {/* AI Gerekçesi */}
                  <div className="space-y-6">
                    <div className="flex items-start gap-8 p-10 bg-indigo-50 rounded-[3rem] border-2 border-indigo-100 shadow-xl transition-all hover:scale-[1.01]">
                      <div className="w-20 h-20 bg-white rounded-[2rem] text-indigo-600 shadow-2xl flex items-center justify-center shrink-0 border-2 border-indigo-50">
                        <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                      </div>
                      <div className="space-y-3">
                        <div className="text-[11px] font-black text-indigo-900 uppercase tracking-[0.5em]">AI DEĞERLENDİRME KRİTERİ</div>
                        <p className="text-lg text-indigo-950 leading-relaxed font-black">{result.reason}</p>
                      </div>
                    </div>

                    <div className="flex items-start gap-8 p-10 bg-amber-50 rounded-[3rem] border-2 border-amber-100 shadow-xl transition-all hover:scale-[1.01]">
                      <div className="w-20 h-20 bg-white rounded-[2rem] text-amber-600 shadow-2xl flex items-center justify-center shrink-0 border-2 border-amber-50">
                        <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>
                      </div>
                      <div className="space-y-3">
                        <div className="text-[11px] font-black text-amber-900 uppercase tracking-[0.5em]">ÖNERİLEN GERİ BİLDİRİM</div>
                        <p className="text-lg text-amber-950 italic font-black leading-relaxed">"{result.feedback}"</p>
                      </div>
                    </div>
                  </div>
                </div>
