import React, { useState } from 'react';
import { Exam, Question } from '../types';

interface ExamSetupProps {
  initialExam: Exam | null;
  onSave: (exam: Exam) => void;
}

const ExamSetup: React.FC<ExamSetupProps> = ({ initialExam, onSave }) => {
  const [classSection, setClassSection] = useState(initialExam?.classSection || '');
  const [courseName, setCourseName] = useState(initialExam?.courseName || '');
  const [examName, setExamName] = useState(initialExam?.examName || '');

  const [questions, setQuestions] = useState<Question[]>(initialExam?.questions || [
    { id: '1', text: '', expectedAnswer: '', keywords: [], maxScore: 10 }
  ]);

  const addQuestion = () => {
    setQuestions([...questions, { 
      id: Date.now().toString(), 
      text: '', 
      expectedAnswer: '', 
      keywords: [], 
      maxScore: 10 
    }]);
  };

  const removeQuestion = (id: string) => {
    setQuestions(questions.filter(q => q.id !== id));
  };

  const updateQuestion = (id: string, field: keyof Question, value: any) => {
    setQuestions(questions.map(q => q.id === id ? { ...q, [field]: value } : q));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!classSection.trim() || !courseName.trim() || !examName.trim() || questions.length === 0) return;
    onSave({
      id: initialExam?.id || Date.now().toString(),
      classSection,
      courseName,
      examName,
      date: new Date().toISOString(),
      questions
    });
  };

  const inputClasses = "w-full px-5 py-4 bg-white border-2 border-slate-200 rounded-[1rem] focus:ring-4 focus:ring-indigo-600/20 focus:border-indigo-600 outline-none transition-all text-indigo-950 font-black text-lg placeholder-indigo-300 shadow-sm";
  const labelClasses = "block text-[11px] font-black text-indigo-900 mb-3 uppercase tracking-[0.25em]";

  return (
    <div className="animate-fade-in max-w-4xl mx-auto pb-20">
      <div className="mb-12 p-8 bg-slate-900 border-l-8 border-indigo-600 rounded-[2.5rem] shadow-2xl">
        <h2 className="text-5xl font-black text-white uppercase tracking-tighter leading-none mb-4">Sınav Yapılandırması</h2>
        <p className="text-indigo-400 font-bold text-lg">Yapay zeka asistanını bu sınav için özel olarak eğitin.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-12">
        {/* Sınav Bilgileri Bölümü */}
        <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl relative overflow-hidden">
          <div className="bg-slate-900 p-6 border-b border-indigo-900">
             <h3 className="text-xs font-black text-white uppercase tracking-[0.4em]">TEMEL SINAV BİLGİLERİ</h3>
          </div>
          <div className="p-10 grid grid-cols-1 md:grid-cols-3 gap-8">
            <div>
              <label className={labelClasses}>Sınıf / Şube</label>
              <input 
                type="text" 
                value={classSection}
                onChange={(e) => setClassSection(e.target.value)}
                placeholder="10-A"
                className={inputClasses}
                required
              />
            </div>
            <div>
              <label className={labelClasses}>Ders Adı</label>
              <input 
                type="text" 
                value={courseName}
                onChange={(e) => setCourseName(e.target.value)}
                placeholder="Biyoloji"
                className={inputClasses}
                required
              />
            </div>
            <div>
              <label className={labelClasses}>Sınav Adı</label>
              <input 
                type="text" 
                value={examName}
                onChange={(e) => setExamName(e.target.value)}
                placeholder="1. Yazılı"
                className={inputClasses}
                required
              />
            </div>
          </div>
        </div>

        {/* Sorular Bölümü */}
        <div className="space-y-8">
          <div className="flex items-end justify-between px-4 p-6 bg-slate-900 border-2 border-indigo-900 rounded-[2.5rem] shadow-xl">
            <div>
              <h3 className="text-2xl font-black text-white uppercase tracking-tight">Soru Listesi</h3>
              <p className="text-indigo-400 text-sm font-bold uppercase tracking-widest mt-1">Rubrik değerlerini belirleyin</p>
            </div>
            <span className="text-sm font-black text-white bg-indigo-600 px-6 py-3 rounded-2xl shadow-xl border-b-4 border-indigo-800">
              TOPLAM: {questions.reduce((a, b) => a + b.maxScore, 0)} PUAN
            </span>
          </div>

          {questions.map((q, index) => (
            <div key={q.id} className="bg-white rounded-[3rem] border border-slate-200 shadow-xl relative group transition-all hover:shadow-[0_25px_60px_-15px_rgba(0,0,0,0.1)] overflow-hidden">
              <div className="bg-slate-900 p-6 flex justify-between items-center border-b border-indigo-900">
                 <div className="flex items-center gap-4">
                    <span className="w-10 h-10 flex items-center justify-center bg-indigo-600 text-white rounded-xl font-black text-lg shadow-lg">
                      {index + 1}
                    </span>
                    <h4 className="text-white font-black text-xs uppercase tracking-widest">SORU DETAYI</h4>
                 </div>
                 <button 
                  type="button"
                  onClick={() => removeQuestion(q.id)}
                  className="text-slate-400 hover:text-rose-500 transition-colors p-2 hover:bg-slate-800 rounded-xl"
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                </button>
