                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                      <div>
                        <label className={labelClasses}>İdeal Doğru Cevap</label>
                        <textarea 
                          value={q.expectedAnswer}
                          onChange={(e) => updateQuestion(q.id, 'expectedAnswer', e.target.value)}
                          placeholder="Örnek ideal yanıt..."
                          className={`${inputClasses} min-h-[120px] leading-relaxed py-5`}
                          required
                        />
                      </div>
                      <div>
                        <label className={labelClasses}>Kritik Kavramlar</label>
                        <input 
                          type="text"
                          value={q.keywords.join(', ')}
                          onChange={(e) => updateQuestion(q.id, 'keywords', e.target.value.split(',').map(s => s.trim()))}
                          placeholder="Örn: fotosentez, kloroplast"
                          className={inputClasses}
                        />
                        <div className="mt-6 flex flex-wrap gap-2">
                          {q.keywords.filter(k => k).map((k, i) => (
                            <span key={i} className="px-4 py-2 bg-indigo-950 text-indigo-200 text-[11px] font-black rounded-xl border border-indigo-900 shadow-sm uppercase tracking-wider">{k}</span>
                          ))}
                        </div>
                      </div>
                    </div>

                    <div className="w-48 bg-slate-900 p-6 rounded-[2rem] border-2 border-indigo-900">
                      <label className="block text-[11px] font-black text-indigo-400 mb-3 uppercase tracking-[0.25em]">Soru Puanı</label>
                      <input 
                        type="number"
                        value={q.maxScore}
                        onChange={(e) => updateQuestion(q.id, 'maxScore', parseInt(e.target.value) || 0)}
                        className="w-full h-16 bg-white border-2 border-indigo-400 rounded-xl text-center text-3xl font-black text-indigo-950 shadow-inner outline-none focus:ring-4 focus:ring-indigo-500/20"
                      />
