                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="flex flex-col sm:flex-row gap-8 pt-12">
          <button 
            type="button"
            onClick={addQuestion}
            className="flex-1 py-6 border-4 border-dashed border-slate-700 rounded-[2.5rem] text-slate-500 hover:border-indigo-500 hover:text-indigo-400 transition-all font-black text-sm tracking-[0.3em] uppercase flex items-center justify-center gap-4 active:scale-95 bg-slate-900/40"
          >
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
            Yeni Soru Ekle
