          <button 
            type="submit"
            className="flex-1 py-6 bg-indigo-600 text-white rounded-[2.5rem] hover:bg-indigo-700 transition-all font-black text-sm tracking-[0.3em] uppercase shadow-[0_20px_50px_rgba(79,70,229,0.4)] active:scale-95 border-b-8 border-indigo-800"
          >
            Sınavı Kaydet ve İlerle
          </button>
        </div>
      </form>
    </div>
  );
};

export default ExamSetup;

import React, { useState } from 'react';
import { StudentSubmission, Exam, GradingResult } from '../types';

interface GradingDetailProps {
  submission: StudentSubmission;
  exam: Exam;
  onBack: () => void;
  onUpdate: (submission: StudentSubmission) => void;
}

const GradingDetail: React.FC<GradingDetailProps> = ({ submission, exam, onBack, onUpdate }) => {
  const [editedSubmission, setEditedSubmission] = useState(submission);
  const [approvedIds, setApprovedIds] = useState<Set<string>>(new Set());
  const [editingId, setEditingId] = useState<string | null>(null);

  const handleScoreChange = (qId: string, newScore: number) => {
    const max = exam.questions.find(q => q.id === qId)?.maxScore || 100;
    const score = Math.min(Math.max(0, newScore), max);

    const updatedResults = editedSubmission.results.map(r => 
      r.questionId === qId ? { ...r, score } : r
    );
    const total = updatedResults.reduce((acc, curr) => acc + curr.score, 0);

    setEditedSubmission({ 
      ...editedSubmission, 
      results: updatedResults, 
      totalScore: total,
      status: 'reviewed'
    });
  };

  const approveQuestion = (qId: string) => {
    const newApproved = new Set(approvedIds);
    newApproved.add(qId);
    setApprovedIds(newApproved);
    setEditingId(null);
  };

  const editQuestion = (qId: string) => {
    const newApproved = new Set(approvedIds);
    newApproved.delete(qId);
    setApprovedIds(newApproved);
    setEditingId(qId);
  };

  const handleSave = () => {
    onUpdate(editedSubmission);
    onBack();
  };

  return (
    <div className="animate-fade-in pb-32">
      {/* Sticky Header */}
      <div className="flex items-center justify-between mb-12 bg-slate-900 border-2 border-indigo-900 p-5 rounded-[2.5rem] backdrop-blur-xl sticky top-24 z-40 shadow-2xl">
        <button 
          onClick={onBack}
          className="flex items-center gap-4 text-indigo-300 hover:text-white font-black text-xs tracking-[0.25em] transition-all uppercase group pl-4"
        >
          <svg className="w-7 h-7 group-hover:-translate-x-2 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
          SONUÇLARA DÖN
        </button>
        <div className="flex gap-6">
          <button 
            onClick={handleSave}
            className="px-12 py-5 bg-indigo-600 text-white rounded-[1.5rem] font-black text-sm tracking-[0.25em] hover:bg-indigo-500 transition-all shadow-[0_15px_40px_rgba(79,70,229,0.3)] uppercase active:scale-95 border-b-8 border-indigo-800"
          >
            NOTLARI SİSTEME İŞLE
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        {/* Sol Panel: Öğrenci Verileri */}
        <div className="lg:col-span-4 space-y-8">
          <div className="bg-white rounded-[3rem] border-2 border-slate-100 shadow-2xl sticky top-52 overflow-hidden">
            <div className="bg-slate-900 p-6 border-b border-indigo-900">
               <h3 className="text-[12px] font-black text-white uppercase tracking-[0.5em]">ÖĞRENCİ KİMLİK KARTI</h3>
            </div>

            <div className="p-8 space-y-6">
               <div>
                  <div className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.2em] mb-2">AD SOYAD</div>
                  <div className="text-4xl font-black text-indigo-950 tracking-tighter leading-none">{submission.studentName}</div>
               </div>
               <div className="grid grid-cols-2 gap-8">
                  <div className="bg-slate-900 p-4 rounded-2xl border border-indigo-900">
                    <div className="text-[9px] font-black text-indigo-400 uppercase tracking-widest mb-1">DERS</div>
                    <div className="text-sm font-black text-white uppercase tracking-tighter">{exam.courseName}</div>
                  </div>
                  <div className="bg-slate-900 p-4 rounded-2xl border border-indigo-900">
                    <div className="text-[9px] font-black text-indigo-400 uppercase tracking-widest mb-1">SINIF</div>
                    <div className="text-sm font-black text-white uppercase tracking-tighter">{exam.classSection}</div>
                  </div>
               </div>

               <div className="aspect-[3/4] rounded-[2.5rem] overflow-hidden bg-slate-950 border-8 border-slate-50 shadow-2xl group relative cursor-zoom-in mb-6">
                <img src={submission.imageUrl} alt="Original" className="w-full h-full object-contain transition-all duration-700 group-hover:scale-125" />
                <div className="absolute inset-0 bg-indigo-950/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center backdrop-blur-sm">
                   <span className="bg-white text-indigo-950 px-6 py-3 rounded-2xl font-black text-xs tracking-widest shadow-2xl uppercase">KAĞIDI İNCELE</span>
                </div>
              </div>

              <div className="p-10 bg-indigo-950 text-white rounded-[2.5rem] shadow-[0_30px_70px_-15px_rgba(30,27,75,0.6)] border-b-8 border-indigo-900 transform hover:scale-105 transition-transform">
                <div className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.4em] mb-3">TOPLAM SINAV NOTU</div>
                <div className="flex items-baseline gap-3">
                   <span className="text-8xl font-black tracking-tighter leading-none">{editedSubmission.totalScore}</span>
                   <span className="text-2xl font-black text-indigo-400 uppercase tracking-tighter">/ 100</span>
                </div>
