                    </div>
                    <div className="bg-emerald-50 p-8 rounded-[2.5rem] border-2 border-emerald-100 relative transition-all hover:bg-white hover:shadow-xl">
                      <div className="absolute -top-4 left-8 px-5 py-2 bg-slate-900 border-2 border-emerald-600 rounded-2xl text-[10px] font-black text-white uppercase tracking-[0.3em] shadow-sm">İDEAL REFERANS</div>
