import { GoogleGenAI, Type } from "@google/genai";
import { Exam, GradingResult, StudentSubmission } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const gradeSubmission = async (
  exam: Exam,
  submission: StudentSubmission
): Promise<{ results: GradingResult[]; totalScore: number }> => {
  const model = 'gemini-3-flash-preview';
  const isMultipleChoice = exam.type === 'multiple-choice';

  const systemInstruction = `
    Sen uzman bir kıdemli öğretmensin. Görevin, ${isMultipleChoice ? 'Çoktan Seçmeli (Test)' : 'Açık Uçlu (Yazılı)'} sınav kağıdını analiz etmektir.

    ${isMultipleChoice ? `
    TEST ANALİZ KURALLARI:
    1. Her soru için öğrencinin işaretlediği seçeneği (A, B, C, D veya E) tespit et.
    2. Eğer öğrenci hiçbir seçeneği işaretlememişse selectedOption kısmını "BOŞ" olarak işaretle.
    3. Eğer işaretleme belirsizse en olası olanı seç ve confidence değerini düşür.
    4. PUANLAMA: selectedOption ile expectedAnswer aynıysa tam puan ver, değilse 0 ver.
    ` : `
    YAZILI ANALİZ KURALLARI:
    1. OCR: El yazısını metne çevir.
    2. ANLAMSAL DEĞERLENDİRME: İdeal Yanıt ile öğrenci yanıtını anlamsal olarak kıyasla.
    3. PUANLAMA: Rubrik ve anahtar kavramlara göre puanı dağıt.
    `}

    GERİ BİLDİRİM (FEEDBACK):
    Öğrenciye pedagojik, açıklayıcı ve nazik bir dille geri bildirim ver. 
    ${isMultipleChoice ? 'Yanlış cevaplarda doğru seçeneği belirt ve nedenini kısaca açıkla.' : 'Eksik kavramları ve gelişim önerilerini belirt.'}

    Kesinlikle JSON formatında yanıt ver.
  `;

  const prompt = `
    SINAV TÜRÜ: ${exam.type === 'multiple-choice' ? 'TEST' : 'KLASİK'}
    SINAV: ${exam.courseName} - ${exam.examName}

    SORULAR VE CEVAP ANAHTARI:
    ${exam.questions.map(q => `
      - ID: ${q.id}
      - SORU: ${q.text || 'Metin belirtilmemiş'}
      - DOĞRU CEVAP: ${q.expectedAnswer}
      ${!isMultipleChoice ? `- KRİTİK KAVRAMLAR: ${q.keywords.join(', ')}` : ''}
      - MAX PUAN: ${q.maxScore}
    `).join('\n')}

    ÖĞRENCİ: ${submission.studentName}
    (Kağıt görüntüsü ektedir. Lütfen her soruyu tek tek analiz et.)

    Dönüş Şeması (JSON Array):
    [{ 
      "questionId": "string", 
      "extractedText": "string",
      ${isMultipleChoice ? '"selectedOption": "A|B|C|D|E|BOŞ",' : ''} 
      "score": number, 
      "reason": "Gerekçe", 
      "feedback": "Öğrenciye not", 
      "confidence": number 
    }]
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: submission.base64Data,
            },
          },
        ],
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              questionId: { type: Type.STRING },
              extractedText: { type: Type.STRING },
              selectedOption: { type: Type.STRING },
              score: { type: Type.NUMBER },
              reason: { type: Type.STRING },
              feedback: { type: Type.STRING },
              confidence: { type: Type.NUMBER },
            },
            required: ["questionId", "extractedText", "score", "reason", "feedback", "confidence"],
          },
        },
      },
    });

    const results: GradingResult[] = JSON.parse(response.text || "[]");
    const totalScore = results.reduce((acc, curr) => acc + curr.score, 0);

    return { results, totalScore };
  } catch (error) {
    console.error("Gemini Grading Error:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { StudentSubmission, Exam, GradingResult } from '../types';

interface GradingDetailProps {
  submission: StudentSubmission;
  exam: Exam;
  onBack: () => void;
  onUpdate: (submission: StudentSubmission) => void;
}

const GradingDetail: React.FC<GradingDetailProps> = ({ submission, exam, onBack, onUpdate }) => {
  const [editedSubmission, setEditedSubmission] = useState(submission);
  const [approvedIds, setApprovedIds] = useState<Set<string>>(new Set());
  const [editingId, setEditingId] = useState<string | null>(null);

  const isTest = exam.type === 'multiple-choice';

  const handleScoreChange = (qId: string, newScore: number) => {
    const max = exam.questions.find(q => q.id === qId)?.maxScore || 100;
    const score = Math.min(Math.max(0, newScore), max);

    const updatedResults = editedSubmission.results.map(r => 
      r.questionId === qId ? { ...r, score } : r
    );
    const total = updatedResults.reduce((acc, curr) => acc + curr.score, 0);

    setEditedSubmission({ 
      ...editedSubmission, 
      results: updatedResults, 
      totalScore: total,
      status: 'reviewed'
    });
  };

  const approveQuestion = (qId: string) => {
    const newApproved = new Set(approvedIds);
    newApproved.add(qId);
    setApprovedIds(newApproved);
    setEditingId(null);
  };

  const editQuestion = (qId: string) => {
    const newApproved = new Set(approvedIds);
    newApproved.delete(qId);
    setApprovedIds(newApproved);
    setEditingId(qId);
  };

  const handleSave = () => {
    onUpdate(editedSubmission);
    onBack();
  };

  return (
    <div className="animate-fade-in pb-32">
      <div className="flex items-center justify-between mb-12 bg-slate-900 border-2 border-indigo-900 p-5 rounded-[2.5rem] backdrop-blur-xl sticky top-24 z-40 shadow-2xl">
        <button onClick={onBack} className="flex items-center gap-4 text-indigo-300 hover:text-white font-black text-xs tracking-[0.25em] transition-all uppercase group pl-4">
          <svg className="w-7 h-7 group-hover:-translate-x-2 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
          SONUÇLARA DÖN
        </button>
        <button onClick={handleSave} className="px-12 py-5 bg-indigo-600 text-white rounded-[1.5rem] font-black text-sm tracking-[0.25em] hover:bg-indigo-500 transition-all shadow-[0_15px_40px_rgba(79,70,229,0.3)] uppercase border-b-8 border-indigo-800">
          NOTLARI SİSTEME İŞLE
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        <div className="lg:col-span-4 space-y-8">
          <div className="bg-white rounded-[3rem] border-2 border-slate-100 shadow-2xl sticky top-52 overflow-hidden">
            <div className="bg-slate-900 p-6 border-b border-indigo-900">
               <h3 className="text-[12px] font-black text-white uppercase tracking-[0.5em]">{isTest ? 'TEST SONUÇ KARTI' : 'ÖĞRENCİ KİMLİK KARTI'}</h3>
            </div>

            <div className="p-8 space-y-6">
               <div>
                  <div className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.2em] mb-2">AD SOYAD</div>
                  <div className="text-4xl font-black text-indigo-950 tracking-tighter leading-none">{submission.studentName}</div>
               </div>

               <div className="aspect-[3/4] rounded-[2.5rem] overflow-hidden bg-slate-950 border-8 border-slate-50 shadow-2xl mb-6">
                <img src={submission.imageUrl} alt="Original" className="w-full h-full object-contain" />
              </div>

              <div className="p-10 bg-indigo-950 text-white rounded-[2.5rem] border-b-8 border-indigo-900">
                <div className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.4em] mb-3">TOPLAM PUAN</div>
                <div className="flex items-baseline gap-3">
                   <span className="text-8xl font-black tracking-tighter leading-none">{editedSubmission.totalScore}</span>
                   <span className="text-2xl font-black text-indigo-400 uppercase tracking-tighter">/ 100</span>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-8 space-y-12">
          <div className="flex items-center gap-6 mb-4 px-6 py-8 bg-slate-900 border-2 border-indigo-900 rounded-[3rem] shadow-2xl">
             <div className="w-16 h-16 bg-emerald-500 rounded-[1.5rem] flex items-center justify-center text-white shadow-2xl">
                <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
             </div>
             <div>
                <h3 className="text-3xl font-black text-white uppercase tracking-tight">Değerlendirme Onayı</h3>
                <p className="text-indigo-400 font-bold text-lg">{isTest ? 'AI tarafından tespit edilen şıkları kontrol edin.' : 'AI puanlarını onaylayın veya düzeltin.'}</p>
             </div>
          </div>

          {exam.questions.map((q, idx) => {
            const result = editedSubmission.results.find(r => r.questionId === q.id);
            if (!result) return null;
            const isApproved = approvedIds.has(q.id);
            const isEditing = editingId === q.id;

            return (
              <div key={q.id} className={`bg-white rounded-[3.5rem] border-2 shadow-2xl overflow-hidden text-indigo-950 transition-all group relative ${isApproved ? 'border-emerald-200' : 'border-slate-100'}`}>
                <div className={`absolute top-0 left-0 w-3 h-full transition-colors ${isApproved ? 'bg-emerald-500' : 'bg-slate-100 group-hover:bg-indigo-600'}`}></div>

                <div className={`p-10 border-b-2 flex flex-col sm:flex-row items-center justify-between gap-8 ${isApproved ? 'bg-emerald-50/50 border-emerald-100' : 'bg-slate-900 border-indigo-900'}`}>
                  <div className="flex items-center gap-6">
                    <span className={`w-16 h-16 text-white rounded-[1.5rem] flex items-center justify-center text-2xl font-black shadow-2xl ${isApproved ? 'bg-emerald-600' : 'bg-indigo-600'}`}>{idx + 1}</span>
                    <div>
                       <h4 className={`font-black text-xs uppercase tracking-[0.4em] mb-1 ${isApproved ? 'text-indigo-950' : 'text-white'}`}>ANALİZ</h4>
                       <span className={`px-3 py-1 bg-white border rounded-lg text-[10px] font-black uppercase tracking-widest ${isApproved ? 'border-emerald-200 text-emerald-600' : 'border-indigo-400 text-indigo-600'}`}>
                         {isApproved ? 'ONAYLANDI' : `GÜVEN: %${Math.round(result.confidence * 100)}`}
                       </span>
                    </div>
                  </div>

                  <div className={`flex items-center gap-6 p-6 rounded-[2rem] shadow-2xl border-2 ${isApproved ? 'bg-white border-emerald-100' : 'bg-slate-800 border-indigo-500'}`}>
                    <div className="flex flex-col items-center">
                       <span className={`text-[10px] font-black uppercase tracking-[0.3em] mb-2 ${isApproved ? 'text-indigo-300' : 'text-indigo-400'}`}>PUAN</span>
                       <div className="flex items-center gap-4">
                          <input type="number" max={q.maxScore} min={0} value={result.score} readOnly={!isEditing} onChange={(e) => handleScoreChange(q.id, parseInt(e.target.value) || 0)} className={`w-32 px-4 py-4 border-4 rounded-[1.25rem] text-center font-black text-5xl outline-none transition-all bg-white ${isEditing ? 'border-indigo-600 text-indigo-900 ring-8 ring-indigo-50/20' : 'border-indigo-100 text-indigo-950'}`} />
                          <span className={`font-black text-4xl ${isApproved ? 'text-indigo-200' : 'text-indigo-400'}`}>/ {q.maxScore}</span>
                       </div>
                    </div>

                    <div className="flex flex-col gap-3 ml-4">
                      {!isApproved && !isEditing ? (
                        <div className="flex gap-2">
