                          <button onClick={() => editQuestion(q.id)} className="px-6 py-2.5 bg-amber-500 text-white rounded-xl font-black text-[11px] tracking-widest uppercase hover:bg-amber-400 transition-all shadow-lg active:scale-95">DÜZELT</button>
                        </div>
                      ) : (
                        <button onClick={() => (isEditing ? approveQuestion(q.id) : editQuestion(q.id))} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-black text-[11px] tracking-widest uppercase">{isEditing ? 'KAYDET' : 'DÜZENLE'}</button>
                      )}
                    </div>
                  </div>
                </div>

                <div className="p-10 space-y-12">
                  <div className="bg-slate-950 text-slate-100 p-8 rounded-[2rem] shadow-2xl relative">
                     <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em] mb-4 block">SORU METNİ</span>
                     <p className="text-lg font-bold leading-relaxed">{q.text || `${idx + 1}. Soru`}</p>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                    <div className="bg-slate-50 p-8 rounded-[2.5rem] border-2 border-slate-100 relative group">
                      <div className="absolute -top-4 left-8 px-5 py-2 bg-slate-900 border-2 border-indigo-900 rounded-2xl text-[10px] font-black text-white uppercase tracking-[0.3em]">ÖĞRENCİ YANITI</div>
                      {isTest ? (
                        <div className="flex items-center gap-6 mt-4">
                          <div className={`w-20 h-20 rounded-2xl flex items-center justify-center text-4xl font-black shadow-xl border-4 ${result.selectedOption === q.expectedAnswer ? 'bg-emerald-100 border-emerald-500 text-emerald-700' : 'bg-rose-100 border-rose-500 text-rose-700'}`}>
                            {result.selectedOption || '...'}
                          </div>
                          <p className="text-indigo-950 font-black uppercase text-xs tracking-widest">Tespit Edilen Şık</p>
                        </div>
                      ) : (
                        <p className="text-indigo-950 text-lg leading-relaxed font-black italic border-l-8 border-indigo-200 pl-6 mt-4">"{result.extractedText || "Okunamadı..."}"</p>
                      )}
                    </div>

                    <div className="bg-emerald-50 p-8 rounded-[2.5rem] border-2 border-emerald-100 relative">
                      <div className="absolute -top-4 left-8 px-5 py-2 bg-slate-900 border-2 border-emerald-600 rounded-2xl text-[10px] font-black text-white uppercase tracking-[0.3em]">CEVAP ANAHTARI</div>
                      {isTest ? (
                        <div className="flex items-center gap-6 mt-4">
                          <div className="w-20 h-20 bg-emerald-600 rounded-2xl flex items-center justify-center text-4xl font-black text-white shadow-xl">
                            {q.expectedAnswer}
