                      ) : (
                        <p className="text-emerald-950 text-lg leading-relaxed font-bold border-l-8 border-emerald-200 pl-6 mt-4">{q.expectedAnswer}</p>
                      )}
                    </div>
                  </div>

                  <div className="space-y-6">
                    <div className="flex items-start gap-8 p-10 bg-indigo-50 rounded-[3rem] border-2 border-indigo-100 shadow-xl">
                      <div className="w-20 h-20 bg-slate-900 rounded-[2rem] text-indigo-400 flex items-center justify-center shrink-0 border-2 border-indigo-900 shadow-xl">
                        <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                      </div>
                      <div className="space-y-3">
                        <div className="text-[11px] font-black text-indigo-900 uppercase tracking-[0.5em]">AI ANALİZİ</div>
                        <p className="text-lg text-indigo-950 leading-relaxed font-black">{result.reason}</p>
                      </div>
                    </div>

                    <div className="flex items-start gap-8 p-10 bg-amber-50 rounded-[3rem] border-2 border-amber-100 shadow-xl">
                      <div className="w-20 h-20 bg-slate-900 rounded-[2rem] text-amber-500 flex items-center justify-center shrink-0 border-2 border-indigo-900 shadow-xl">
                        <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" /></svg>
                      </div>
                      <div className="space-y-3">
                        <div className="text-[11px] font-black text-amber-900 uppercase tracking-[0.5em]">PEDAGOJİK GERİ BİLDİRİM</div>
                        <p className="text-lg text-amber-950 italic font-black leading-relaxed">"{result.feedback}"</p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default GradingDetail;

export interface GradingStep {
  text: string;
  score: number;
}

export interface Question {
  id: string;
  text: string;
  expectedAnswer: string; // Açık uçlu için ideal tam puanlık metin
  keywords: string[];
  maxScore: number;
  gradingSteps?: GradingStep[]; // Öğretmenin belirlediği puanlama basamakları (Rubrik)
  options?: string[]; // Test soruları için seçenekler
}

export interface Exam {
  id: string;
  type: 'open-ended' | 'multiple-choice';
  classSection: string;
  courseName: string;
  examName: string;
  date: string;
  questions: Question[];
}

export interface GradingResult {
  questionId: string;
  extractedText: string;
  selectedOption?: string; // Test için öğrencinin seçtiği şık
  score: number;
  reason: string;
  feedback: string;
  confidence: number;
}

export interface StudentSubmission {
  id: string;
  studentName: string;
  imageUrl: string;
  base64Data: string;
  status: 'pending' | 'processing' | 'graded' | 'reviewed';
  results: GradingResult[];
  totalScore: number;
}

import React, { useState } from 'react';
import { Exam, Question, GradingStep } from '../types';

interface ExamSetupProps {
  initialExam: Exam | null;
  onSave: (exam: Exam) => void;
}

const ExamSetup: React.FC<ExamSetupProps> = ({ initialExam, onSave }) => {
  const [examType, setExamType] = useState<'open-ended' | 'multiple-choice'>(initialExam?.type || 'open-ended');
  const [classSection, setClassSection] = useState(initialExam?.classSection || '');
  const [courseName, setCourseName] = useState(initialExam?.courseName || '');
  const [examName, setExamName] = useState(initialExam?.examName || '');

  const [questions, setQuestions] = useState<Question[]>(initialExam?.questions || [
    { id: '1', text: '', expectedAnswer: examType === 'multiple-choice' ? 'A' : '', keywords: [], maxScore: 10, gradingSteps: [] }
  ]);

  const addQuestion = () => {
    setQuestions([...questions, { 
      id: Date.now().toString(), 
      text: '', 
      expectedAnswer: examType === 'multiple-choice' ? 'A' : '', 
      keywords: [], 
      maxScore: 10,
      gradingSteps: []
    }]);
  };

  const removeQuestion = (id: string) => {
    setQuestions(questions.filter(q => q.id !== id));
  };

  const updateQuestion = (id: string, field: keyof Question, value: any) => {
    setQuestions(questions.map(q => q.id === id ? { ...q, [field]: value } : q));
  };

  const addGradingStep = (qId: string) => {
    setQuestions(questions.map(q => {
      if (q.id === qId) {
        const steps = q.gradingSteps || [];
        return { ...q, gradingSteps: [...steps, { text: '', score: 0 }] };
      }
      return q;
    }));
  };

  const removeGradingStep = (qId: string, index: number) => {
    setQuestions(questions.map(q => {
      if (q.id === qId && q.gradingSteps) {
        return { ...q, gradingSteps: q.gradingSteps.filter((_, i) => i !== index) };
      }
      return q;
    }));
  };

  const updateGradingStep = (qId: string, index: number, field: keyof GradingStep, value: any) => {
    setQuestions(questions.map(q => {
      if (q.id === qId && q.gradingSteps) {
        const newSteps = [...q.gradingSteps];
        newSteps[index] = { ...newSteps[index], [field]: value };
        return { ...q, gradingSteps: newSteps };
      }
      return q;
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!classSection.trim() || !courseName.trim() || !examName.trim() || questions.length === 0) return;
    onSave({
      id: initialExam?.id || Date.now().toString(),
      type: examType,
      classSection,
      courseName,
      examName,
      date: new Date().toISOString(),
      questions
    });
  };

  const inputClasses = "w-full px-5 py-4 bg-white border-2 border-slate-200 rounded-[1rem] focus:ring-4 focus:ring-indigo-600/20 focus:border-indigo-600 outline-none transition-all text-indigo-950 font-black text-lg placeholder-indigo-300 shadow-sm";
  const labelClasses = "block text-[11px] font-black text-indigo-900 mb-3 uppercase tracking-[0.25em]";

  return (
    <div className="animate-fade-in max-w-4xl mx-auto pb-20">
      <div className="mb-12 p-8 bg-slate-900 border-l-8 border-indigo-600 rounded-[2.5rem] shadow-2xl">
        <h2 className="text-5xl font-black text-white uppercase tracking-tighter leading-none mb-4">Sınav Yapılandırması</h2>
        <p className="text-indigo-400 font-bold text-lg">Değerlendirme kriterlerini ve sınav tipini belirleyin.</p>
      </div>

      <div className="flex gap-4 mb-12">
        <button 
          type="button"
          onClick={() => setExamType('open-ended')}
          className={`flex-1 p-8 rounded-[2rem] border-4 transition-all text-left group ${examType === 'open-ended' ? 'bg-indigo-600 border-indigo-400 text-white shadow-xl shadow-indigo-950/50' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-indigo-900'}`}
        >
          <div className={`w-12 h-12 rounded-xl flex items-center justify-center mb-4 transition-colors ${examType === 'open-ended' ? 'bg-white text-indigo-600' : 'bg-slate-800 text-slate-500'}`}>
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
          </div>
          <div className="font-black text-xl uppercase tracking-tighter">Yazılı / Açık Uçlu</div>
          <div className={`text-xs mt-1 font-bold ${examType === 'open-ended' ? 'text-indigo-200' : 'text-slate-600'}`}>Rubrik ve basamaklı puanlama.</div>
        </button>

        <button 
          type="button"
          onClick={() => setExamType('multiple-choice')}
          className={`flex-1 p-8 rounded-[2rem] border-4 transition-all text-left group ${examType === 'multiple-choice' ? 'bg-indigo-600 border-indigo-400 text-white shadow-xl shadow-indigo-950/50' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-indigo-900'}`}
        >
          <div className={`w-12 h-12 rounded-xl flex items-center justify-center mb-4 transition-colors ${examType === 'multiple-choice' ? 'bg-white text-indigo-600' : 'bg-slate-800 text-slate-500'}`}>
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          </div>
          <div className="font-black text-xl uppercase tracking-tighter">Test Değerlendirmesi</div>
          <div className={`text-xs mt-1 font-bold ${examType === 'multiple-choice' ? 'text-indigo-200' : 'text-slate-600'}`}>Seçenekli hızlı okuma.</div>
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-12">
        {/* SINAV KARTI */}
        <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl overflow-hidden">
          <div className="bg-slate-900 p-6 border-b border-indigo-900">
             <h3 className="text-xs font-black text-white uppercase tracking-[0.4em]">SINAV GENEL BİLGİLERİ</h3>
          </div>
          <div className="p-10 grid grid-cols-1 md:grid-cols-3 gap-8">
            <div>
              <label className={labelClasses}>Sınıf / Şube</label>
              <input type="text" value={classSection} onChange={(e) => setClassSection(e.target.value)} placeholder="10-A" className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Ders Adı</label>
              <input type="text" value={courseName} onChange={(e) => setCourseName(e.target.value)} placeholder="Biyoloji" className={inputClasses} required />
            </div>
            <div>
              <label className={labelClasses}>Sınav Adı</label>
              <input type="text" value={examName} onChange={(e) => setExamName(e.target.value)} placeholder="1. Yazılı" className={inputClasses} required />
            </div>
          </div>
        </div>

        {/* SORU LİSTESİ */}
        <div className="space-y-10">
          <div className="flex items-end justify-between px-8 p-6 bg-slate-900 border-2 border-indigo-900 rounded-[2.5rem] shadow-xl">
            <div>
              <h3 className="text-2xl font-black text-white uppercase tracking-tight">Sorular ve Puanlama</h3>
              <p className="text-indigo-400 text-sm font-bold uppercase tracking-widest mt-1">Her soru için özel kriterler belirleyin.</p>
            </div>
            <span className="text-sm font-black text-white bg-indigo-600 px-6 py-3 rounded-2xl shadow-xl border-b-4 border-indigo-800">
              TOPLAM: {questions.reduce((a, b) => a + b.maxScore, 0)} PUAN
            </span>
          </div>

          {questions.map((q, index) => (
            <div key={q.id} className="bg-white rounded-[3.5rem] border border-slate-200 shadow-xl overflow-hidden group">
              <div className="bg-slate-900 p-6 flex justify-between items-center border-b border-indigo-900">
                 <div className="flex items-center gap-4">
                    <span className="w-12 h-12 flex items-center justify-center bg-indigo-600 text-white rounded-2xl font-black text-xl shadow-lg">{index + 1}</span>
                    <h4 className="text-white font-black text-xs uppercase tracking-[0.4em]">SORU YAPILANDIRMASI</h4>
                 </div>
                 <button type="button" onClick={() => removeQuestion(q.id)} className="text-slate-400 hover:text-rose-500 transition-colors p-3 hover:bg-slate-800 rounded-2xl">
                   <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                 </button>
              </div>

