                <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                  {examType === 'open-ended' ? (
                    <div className="lg:col-span-2 space-y-10">
                      <div>
                        <label className={labelClasses}>İdeal Tam Puanlık Cevap</label>
                        <textarea value={q.expectedAnswer} onChange={(e) => updateQuestion(q.id, 'expectedAnswer', e.target.value)} placeholder="Tam puan alacak cevap örneği..." className={`${inputClasses} min-h-[120px] leading-relaxed py-5`} required />
                      </div>

                      {/* Basamaklı Puanlama (Rubrik) Alanı */}
                      <div className="bg-slate-50 p-8 rounded-[2.5rem] border-2 border-slate-100 shadow-inner">
                        <div className="flex items-center justify-between mb-8 border-b-2 border-slate-200 pb-4">
