                                  value={step.text} 
                                  onChange={(e) => updateGradingStep(q.id, sIdx, 'text', e.target.value)}
                                  placeholder="Kriter / Açıklama (Örn: Sadece evre isimlerini yazarsa)" 
                                  className={`${inputClasses} py-3 text-sm`} 
                                />
                              </div>
                              <div className="w-24 shrink-0">
                                <input 
                                  type="number" 
                                  value={step.score} 
                                  onChange={(e) => updateGradingStep(q.id, sIdx, 'score', parseInt(e.target.value) || 0)}
                                  className={`${inputClasses} py-3 text-sm text-center`} 
                                />
                              </div>
                              <button 
                                type="button" 
                                onClick={() => removeGradingStep(q.id, sIdx)}
                                className="p-4 text-rose-500 hover:bg-rose-50 rounded-xl transition-colors"
                              >
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                              </button>
                            </div>
                          ))}
                          {(!q.gradingSteps || q.gradingSteps.length === 0) && (
                            <div className="text-center py-6 text-slate-400 font-black text-[10px] uppercase tracking-widest border-2 border-dashed border-slate-200 rounded-2xl">Henüz özel puanlama basamağı eklenmedi.</div>
                          )}
                        </div>
                      </div>
                    </div>
                  ) : (
                    <div className="lg:col-span-2">
                      <label className={labelClasses}>Doğru Seçenek</label>
                      <div className="flex gap-4">
                        {['A', 'B', 'C', 'D', 'E'].map(opt => (
                          <button 
                            key={opt}
                            type="button"
                            onClick={() => updateQuestion(q.id, 'expectedAnswer', opt)}
                            className={`flex-1 py-8 rounded-3xl font-black text-3xl border-4 transition-all ${q.expectedAnswer === opt ? 'bg-indigo-600 border-indigo-400 text-white shadow-xl scale-105' : 'bg-white border-slate-100 text-indigo-950 hover:bg-slate-50'}`}
                          >
                            {opt}
                          </button>
                        ))}
                      </div>
                    </div>
                  )}
                </div>

                <div className="flex items-center gap-10 pt-8 border-t-2 border-slate-50">
                  <div className="w-48 bg-slate-900 p-6 rounded-[2rem] border-2 border-indigo-900">
                    <label className="block text-[11px] font-black text-indigo-400 mb-3 uppercase tracking-[0.25em]">TAM PUAN</label>
                    <input type="number" value={q.maxScore} onChange={(e) => updateQuestion(q.id, 'maxScore', parseInt(e.target.value) || 0)} className="w-full h-16 bg-white border-2 border-indigo-400 rounded-xl text-center text-4xl font-black text-indigo-950 outline-none" />
                  </div>

                  {examType === 'open-ended' && (
                    <div className="flex-grow">
                      <label className={labelClasses}>Kritik Anahtar Kelimeler</label>
                      <input type="text" value={q.keywords.join(', ')} onChange={(e) => updateQuestion(q.id, 'keywords', e.target.value.split(',').map(s => s.trim()))} placeholder="Örn: DNA, RNA, Replikasyon" className={inputClasses} />
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="flex flex-col sm:flex-row gap-8 pt-12 border-t-4 border-slate-900">
          <button type="button" onClick={addQuestion} className="flex-1 py-8 border-4 border-dashed border-slate-700 rounded-[2.5rem] text-slate-500 hover:border-indigo-500 hover:text-indigo-400 transition-all font-black text-sm tracking-[0.4em] uppercase flex items-center justify-center gap-4 bg-slate-900/40">
            <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" /></svg>
            Soru Ekle
          </button>
          <button type="submit" className="flex-1 py-8 bg-indigo-600 text-white rounded-[2.5rem] hover:bg-indigo-700 font-black text-sm tracking-[0.4em] uppercase shadow-[0_30px_60px_rgba(79,70,229,0.3)] border-b-[10px] border-indigo-800 active:translate-y-2 active:border-b-0 transition-all">
            Yapılandırmayı Kaydet
          </button>
        </div>
      </form>
    </div>
  );
};

