import { GoogleGenAI, Type } from "@google/genai";
import { Exam, GradingResult, StudentSubmission, Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const generateQuestions = async (
  grade: string,
  course: string,
  outcome: string,
  count: number = 3
): Promise<Question[]> => {
  const model = 'gemini-3-pro-preview'; // Reasoning focus

  const systemInstruction = `
    Sen uzman bir eğitim teknolojileri uzmanı ve ölçme değerlendirme profesörüsün. 
    Verilen sınıf, ders ve kazanım/öğrenme çıktısına uygun olarak üst düzey düşünme becerilerini (analiz, sentez, değerlendirme) ölçen açık uçlu sınav soruları hazırlarsın.

    KURALLAR:
    1. Her soru için ideal bir cevap (expectedAnswer) oluştur.
    2. Soruda mutlaka olması gereken anahtar kelimeleri (keywords) belirle.
    3. Her soru için basamaklı bir puanlama rubriği (gradingSteps) hazırla (tam puan, kısmi puan durumları).
    4. Sorular pedagojik açıdan net ve anlaşılır olmalıdır.
    5. JSON formatında bir liste döndür.
  `;

  const prompt = `
    DERS: ${course}
    SINIF DÜZEYİ: ${grade}
    KAZANIM / ÖĞRENME ÇIKTISI: "${outcome}"
    İSTENEN SORU SAYISI: ${count}

    Lütfen bu bilgiler ışığında profesyonel sınav soruları hazırla.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              text: { type: Type.STRING },
              expectedAnswer: { type: Type.STRING },
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              maxScore: { type: Type.NUMBER, description: "Genelde 10 veya 20 puan" },
              gradingSteps: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    text: { type: Type.STRING },
                    score: { type: Type.NUMBER }
                  },
                  required: ["text", "score"]
                }
              }
            },
            required: ["text", "expectedAnswer", "keywords", "maxScore", "gradingSteps"]
          }
        }
      }
    });

    const questions: any[] = JSON.parse(response.text || "[]");
    return questions.map((q, i) => ({
      ...q,
      id: `gen-${Date.now()}-${i}`
    }));
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

export const gradeSubmission = async (
  exam: Exam,
  submission: StudentSubmission
): Promise<{ results: GradingResult[]; totalScore: number }> => {
  const model = 'gemini-3-flash-preview';
  const isMultipleChoice = exam.type === 'multiple-choice';

  const systemInstruction = `
    Sen uzman bir kıdemli öğretmensin. Görevin, ${isMultipleChoice ? 'Çoktan Seçmeli (Test)' : 'Açık Uçlu (Yazılı)'} sınav kağıdını analiz etmektir.

    ${isMultipleChoice ? `
    TEST ANALİZ KURALLARI:
    1. Her soru için öğrencinin işaretlediği seçeneği (A, B, C, D veya E) tespit et.
    2. Eğer öğrenci hiçbir seçeneği işaretlememişse selectedOption kısmını "BOŞ" olarak işaretle.
    3. PUANLAMA: selectedOption ile expectedAnswer aynıysa tam puan ver, değilse 0 ver.
    ` : `
    YAZILI ANALİZ KURALLARI:
    1. OCR: El yazısını metne çevir.
    2. ANLAMSAL DEĞERLENDİRME: İdeal Yanıt ile öğrenci yanıtını anlamsal olarak kıyasla.
    3. ÖZEL PUANLAMA (RUBRİK): Soruda belirtilen "PUANLAMA BASAMAKLARI"na (gradingSteps) kesinlikle uy. Öğretmen hangi durum için kaç puan verilmesini istemişse o puanı ver.
    4. PUAN DAĞILIMI: Eğer öğrenci basamakların dışında ama doğru bir şey söylemişse, ideal yanıta yakınlığına ve maxScore limitine göre adilce puan ver.
    `}

    GERİ BİLDİRİM (FEEDBACK):
    Öğrenciye pedagojik, açıklayıcı ve nazik bir dille geri bildirim ver. 
    ${isMultipleChoice ? 'Yanlış cevaplarda doğru seçeneği belirt ve nedenini kısaca açıkla.' : 'Eksik kavramları ve öğretmen rubriğine göre neden o puanı aldığını belirt.'}

    Kesinlikle JSON formatında yanıt ver.
  `;

  const prompt = `
    SINAV TÜRÜ: ${exam.type === 'multiple-choice' ? 'TEST' : 'KLASİK'}
    SINAV: ${exam.courseName} - ${exam.examName}

    SORULAR VE CEVAP ANAHTARI / RUBRİK:
    ${exam.questions.map(q => `
      - ID: ${q.id}
      - SORU: ${q.text || 'Metin belirtilmemiş'}
      - İDEAL TAM PUANLIK CEVAP: ${q.expectedAnswer}
      ${!isMultipleChoice ? `
      - PUANLAMA BASAMAKLARI (RUBRİK): 
        ${q.gradingSteps?.map(step => `* "${step.text}" durumu için: ${step.score} Puan`).join('\n        ') || 'Belirtilmedi'}
      - ANAHTAR KELİMELER: ${q.keywords.join(', ')}
      ` : ''}
      - MAX PUAN: ${q.maxScore}
    `).join('\n')}

    ÖĞRENCİ: ${submission.studentName}
    (Kağıt görüntüsü ektedir. Lütfen her soruyu rubrik basamaklarına göre titizlikle analiz et.)

    Dönüş Şeması (JSON Array):
    [{ 
      "questionId": "string", 
      "extractedText": "string",
      ${isMultipleChoice ? '"selectedOption": "A|B|C|D|E|BOŞ",' : ''} 
      "score": number, 
      "reason": "Öğretmenin belirlediği hangi basamağa/kriterlere göre puan verildiğinin açıklaması", 
      "feedback": "Öğrenciye pedagojik not", 
      "confidence": number 
    }]
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: submission.base64Data,
            },
          },
        ],
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              questionId: { type: Type.STRING },
              extractedText: { type: Type.STRING },
              selectedOption: { type: Type.STRING },
              score: { type: Type.NUMBER },
              reason: { type: Type.STRING },
              feedback: { type: Type.STRING },
              confidence: { type: Type.NUMBER },
            },
            required: ["questionId", "extractedText", "score", "reason", "feedback", "confidence"],
          },
        },
      },
    });

    const results: GradingResult[] = JSON.parse(response.text || "[]");
    const totalScore = results.reduce((acc, curr) => acc + curr.score, 0);

    return { results, totalScore };
  } catch (error) {
    console.error("Gemini Grading Error:", error);
    throw error;
  }
};

