                              type="button" 
                              onClick={() => addGradingStep(q.id)}
                              className="px-4 py-2.5 bg-indigo-950 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-900 transition-all"
                            >
                              Basamak Ekle +
                            </button>
                           </div>
                        </div>

                        <div className="space-y-4">
                          {q.gradingSteps?.map((step, sIdx) => (
                            <div key={sIdx} className="flex gap-4 items-start bg-white p-4 rounded-2xl border border-slate-200 shadow-sm">
                              <div className="flex-grow">
                                <input 
                                  type="text" 
                                  value={step.text} 
                                  onChange={(e) => updateGradingStep(q.id, sIdx, 'text', e.target.value)}
