                                  className="w-full bg-transparent border-none focus:ring-0 text-sm font-bold text-indigo-950 p-0" 
                                />
                              </div>
                              <div className="w-20 shrink-0">
                                <input 
                                  type="number" 
                                  value={step.score} 
                                  onChange={(e) => updateGradingStep(q.id, sIdx, 'score', parseInt(e.target.value) || 0)}
