import { GoogleGenAI, Type } from "@google/genai";
import { Exam, GradingResult, StudentSubmission, Question } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const generateQuestions = async (
  grade: string,
  course: string,
  outcome: string,
  count: number = 3
): Promise<Question[]> => {
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Sen uzman bir eğitim teknolojileri uzmanı ve ölçme değerlendirme profesörüsün. 
    Verilen sınıf, ders ve kazanım/öğrenme çıktısına uygun olarak üst düzey düşünme becerilerini (analiz, sentez, değerlendirme) ölçen açık uçlu sınav soruları hazırlarsın.

    KURALLAR:
    1. Her soru için ideal bir cevap (expectedAnswer) oluştur.
    2. Soruda mutlaka olması gereken anahtar kelimeleri (keywords) belirle.
    3. Her soru için basamaklı bir puanlama rubriği (gradingSteps) hazırla (tam puan, %75, %50, %25 gibi durumlar).
    4. Sorular pedagojik açıdan net ve anlaşılır olmalıdır.
    5. JSON formatında bir liste döndür.
  `;

  const prompt = `
    DERS: ${course}
    SINIF DÜZEYİ: ${grade}
    KAZANIM / ÖĞRENME ÇIKTISI: "${outcome}"
    İSTENEN SORU SAYISI: ${count}

    Lütfen bu bilgiler ışığında profesyonel sınav soruları hazırla.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              text: { type: Type.STRING },
              expectedAnswer: { type: Type.STRING },
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              maxScore: { type: Type.NUMBER },
              gradingSteps: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    text: { type: Type.STRING },
                    score: { type: Type.NUMBER }
                  },
                  required: ["text", "score"]
                }
              }
            },
            required: ["text", "expectedAnswer", "keywords", "maxScore", "gradingSteps"]
          }
        }
      }
    });

    const questions: any[] = JSON.parse(response.text || "[]");
    return questions.map((q, i) => ({
      ...q,
      id: `gen-${Date.now()}-${i}`
    }));
  } catch (error) {
    console.error("Gemini Generation Error:", error);
    throw error;
  }
};

export const gradeSubmission = async (
  exam: Exam,
  submission: StudentSubmission
): Promise<{ results: GradingResult[]; totalScore: number }> => {
  const model = 'gemini-3-flash-preview';
  const isMultipleChoice = exam.type === 'multiple-choice';

  const systemInstruction = `
    Sen uzman bir kıdemli öğretmensin. Görevin, sınav kağıdını titizlikle analiz etmektir.

    ${isMultipleChoice ? `
    TEST ANALİZ KURALLARI:
    1. Seçeneği tespit et.
    2. Doğruysa tam puan, değilse 0 ver.
    ` : `
    YAZILI ANALİZ KURALLARI:
    1. OCR: El yazısını metne dök.
    2. RUBRİK ÖNCELİĞİ: Öğretmenin tanımladığı "PUANLAMA BASAMAKLARI" (gradingSteps) senin ana kılavuzundur. Öğrencinin yanıtı bu basamaklardan hangisine en yakınsa o basamağın puanını ver.
    3. GEREKÇE: Neden o basamağı seçtiğini 'reason' alanında açıkla.
    4. GERİ BİLDİRİM: Öğrenciye gelişim önerisi ver.
    `}

    Kesinlikle JSON formatında yanıt ver.
  `;

  const prompt = `
    SINAV: ${exam.courseName} - ${exam.examName}

    SORULAR VE RUBRİK:
    ${exam.questions.map(q => `
      - ID: ${q.id}
      - SORU: ${q.text}
      - İDEAL CEVAP: ${q.expectedAnswer}
      ${!isMultipleChoice ? `- RUBRİK BASAMAKLARI: ${q.gradingSteps?.map(s => `${s.text} -> ${s.score} Puan`).join(' | ')}` : ''}
      - MAX PUAN: ${q.maxScore}
    `).join('\n')}

    ÖĞRENCİ: ${submission.studentName}
    (Görüntü ektedir.)

    Yanıt Şeması:
    [{ "questionId": "string", "extractedText": "string", "score": number, "reason": "Öğretmenin rubriğine göre gerekçe", "feedback": "Öğrenci notu", "confidence": number }]
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: {
        parts: [
          { text: prompt },
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: submission.base64Data,
            },
          },
        ],
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
      },
    });

    const results: GradingResult[] = JSON.parse(response.text || "[]");
    const totalScore = results.reduce((acc, curr) => acc + curr.score, 0);

    return { results, totalScore };
  } catch (error) {
    console.error("Gemini Grading Error:", error);
    throw error;
  }
};

export interface GradingStep {
  text: string;
  score: number;
}

export interface Question {
  id: string;
  text: string;
  expectedAnswer: string;
  keywords: string[];
  maxScore: number;
  gradingSteps?: GradingStep[];
  options?: string[];
}

export interface Exam {
  id: string;
  type: 'open-ended' | 'multiple-choice';
  classSection: string;
  courseName: string;
  examName: string;
  date: string;
  questions: Question[];
}

export interface GradingResult {
  questionId: string;
  extractedText: string;
  selectedOption?: string;
  score: number;
  reason: string;
  feedback: string;
  confidence: number;
}

export interface StudentSubmission {
  id: string;
  studentName: string;
  imageUrl: string;
  base64Data: string;
  status: 'pending' | 'processing' | 'graded' | 'reviewed';
  results: GradingResult[];
  totalScore: number;
}

export interface UserSettings {
  teacherName: string;
  schoolName: string;
  subject: string;
  theme: 'dark' | 'light' | 'system';
  aiSensitivity: 'low' | 'normal' | 'strict';
}

import React, { useState, useEffect } from 'react';
import { Exam, StudentSubmission, Question, UserSettings } from './types';
import Header from './components/Header';
import ExamSetup from './components/ExamSetup';
import UploadSection from './components/UploadSection';
import GradingDashboard from './components/GradingDashboard';
import GradingDetail from './components/GradingDetail';
import AnalyticsView from './components/AnalyticsView';
import QuestionPrep from './components/QuestionPrep';
import SettingsPanel from './components/SettingsPanel';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'setup' | 'upload' | 'dashboard' | 'detail' | 'analytics' | 'question-prep' | 'settings'>('setup');
  const [exam, setExam] = useState<Exam | null>(null);
  const [submissions, setSubmissions] = useState<StudentSubmission[]>([]);
  const [selectedSubmissionId, setSelectedSubmissionId] = useState<string | null>(null);
  const [prefilledQuestions, setPrefilledQuestions] = useState<Question[]>([]);
  const [settings, setSettings] = useState<UserSettings>({
    teacherName: '',
    schoolName: '',
    subject: '',
    theme: 'dark',
    aiSensitivity: 'normal'
  });

  // Persistence & Theme Initialization
  useEffect(() => {
    const savedExam = localStorage.getItem('edugrade_exam');
    const savedSubmissions = localStorage.getItem('edugrade_submissions');
    const savedSettings = localStorage.getItem('edugrade_settings');

    if (savedExam) setExam(JSON.parse(savedExam));
    if (savedSubmissions) setSubmissions(JSON.parse(savedSubmissions));
    if (savedSettings) {
      const parsedSettings = JSON.parse(savedSettings);
      setSettings(parsedSettings);
      applyTheme(parsedSettings.theme);
    } else {
      applyTheme('dark');
    }
  }, []);

  const applyTheme = (theme: 'dark' | 'light' | 'system') => {
    const root = window.document.documentElement;
    if (theme === 'dark' || (theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      root.classList.add('dark');
      root.style.backgroundColor = '#020617'; // slate-950
    } else {
      root.classList.remove('dark');
      root.style.backgroundColor = '#f8fafc'; // slate-50
    }
  };

  const saveToLocal = (updatedExam: Exam | null, updatedSubmissions: StudentSubmission[]) => {
    if (updatedExam) localStorage.setItem('edugrade_exam', JSON.stringify(updatedExam));
    localStorage.setItem('edugrade_submissions', JSON.stringify(updatedSubmissions));
  };

  const handleSettingsUpdate = (newSettings: UserSettings) => {
    setSettings(newSettings);
    localStorage.setItem('edugrade_settings', JSON.stringify(newSettings));
    applyTheme(newSettings.theme);
  };

  const handleExamSaved = (newExam: Exam) => {
    setExam(newExam);
    saveToLocal(newExam, submissions);
    setCurrentView('upload');
  };

  const handleUploadComplete = (newSubmissions: StudentSubmission[]) => {
    const updated = [...submissions, ...newSubmissions];
    setSubmissions(updated);
    saveToLocal(exam, updated);
    setCurrentView('dashboard');
  };

  const handleSubmissionUpdate = (updatedSub: StudentSubmission) => {
    const updated = submissions.map(s => s.id === updatedSub.id ? updatedSub : s);
    setSubmissions(updated);
    saveToLocal(exam, updated);
  };

  const handleQuestionsGenerated = (questions: Question[]) => {
    setPrefilledQuestions(questions);
    setCurrentView('setup');
  };

  const renderView = () => {
    switch (currentView) {
      case 'settings':
        return <SettingsPanel settings={settings} onUpdate={handleSettingsUpdate} onResetAll={() => {
          if(confirm('Tüm veriler (sınavlar, sonuçlar) kalıcı olarak silinecek. Emin misiniz?')) {
            localStorage.clear();
            window.location.reload();
          }
        }} />;
      case 'question-prep':
        return <QuestionPrep onQuestionsGenerated={handleQuestionsGenerated} />;
      case 'setup':
        return <ExamSetup initialExam={exam} onSave={handleExamSaved} prefilledQuestions={prefilledQuestions} />;
      case 'upload':
        return <UploadSection onUpload={handleUploadComplete} exam={exam!} />;
      case 'dashboard':
        return (
          <GradingDashboard 
            submissions={submissions} 
            onSelect={(id) => { setSelectedSubmissionId(id); setCurrentView('detail'); }}
            onReset={() => { if(confirm('Tüm sonuçlar silinecek. Emin misiniz?')) { setSubmissions([]); saveToLocal(exam, []); } }}
            onViewAnalytics={() => setCurrentView('analytics')}
          />
        );
      case 'detail':
        const sub = submissions.find(s => s.id === selectedSubmissionId);
        if (!sub) return null;
        return (
          <GradingDetail 
            submission={sub} 
            exam={exam!} 
            onBack={() => setCurrentView('dashboard')} 
            onUpdate={handleSubmissionUpdate}
          />
        );
      case 'analytics':
        return <AnalyticsView submissions={submissions} exam={exam!} onBack={() => setCurrentView('dashboard')} />;
      default:
        return null;
    }
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${settings.theme === 'light' ? 'bg-slate-50 text-slate-900' : 'bg-slate-950 text-slate-100'}`}>
      <Header 
        currentView={currentView} 
        onNavigate={(view) => setCurrentView(view)} 
        isExamSet={!!exam}
        teacherName={settings.teacherName}
      />
      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        {renderView()}
      </main>
    </div>
  );
};

export default App;

