import React, { useState } from 'react';
import { generateQuestions } from '../services/geminiService';
import { Question } from '../types';

interface QuestionPrepProps {
  onQuestionsGenerated: (questions: Question[]) => void;
}

const QuestionPrep: React.FC<QuestionPrepProps> = ({ onQuestionsGenerated }) => {
  const [grade, setGrade] = useState('');
  const [course, setCourse] = useState('');
  const [outcome, setOutcome] = useState('');
  const [difficulty, setDifficulty] = useState('Orta');
  const [isGenerating, setIsGenerating] = useState(false);
  const [generatedQuestions, setGeneratedQuestions] = useState<Question[]>([]);

  const difficulties = [
    { id: 'Çok Basit', label: 'Çok Basit' },
    { id: 'Basit', label: 'Basit' },
    { id: 'Orta', label: 'Orta' },
    { id: 'Orta Üst', label: 'Orta Üst' },
    { id: 'Olması Gereken', label: 'İdeal (MEB)' }
  ];

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!grade || !course || !outcome) return;

    setIsGenerating(true);
    try {
      const questions = await generateQuestions(grade, course, outcome, difficulty);
      setGeneratedQuestions(questions);
    } catch (err) {
      alert("İçerik hazırlanırken küçük bir sorun oluştu. İstersen tekrar deneyelim.");
    } finally {
      setIsGenerating(false);
    }
  };

  const inputClasses = "w-full px-5 py-4 bg-white dark:bg-slate-900 border-2 border-slate-200 dark:border-slate-800 rounded-2xl focus:border-notera-purple outline-none transition-all text-slate-900 dark:text-white font-bold text-lg";
  const labelClasses = "block text-[10px] font-black text-notera-purple uppercase tracking-[0.2em] mb-2";

  return (
    <div className="animate-fade-in max-w-4xl mx-auto pb-20">
      <div className="mb-12 p-10 bg-notera-purple rounded-[3rem] shadow-xl relative overflow-hidden">
        <div className="relative z-10">
          <h2 className="text-4xl font-black text-white uppercase tracking-tighter mb-4">Examora <span className="text-notera-turquoise italic">Asistanı</span></h2>
          <p className="text-slate-300 font-medium text-lg">Hangi kazanımı ölçmek istiyorsun? Birlikte kurgulayalım.</p>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[3rem] border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden mb-12">
        <form onSubmit={handleGenerate} className="p-10 space-y-10">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
              <label className={labelClasses}>Sınıf Düzeyi</label>
              <select value={grade} onChange={(e) => setGrade(e.target.value)} className={inputClasses} required>
                <option value="">Seçiniz...</option>
                {[5,6,7,8,9,10,11,12].map(n => <option key={n} value={`${n}. Sınıf`}>{n}. Sınıf</option>)}
              </select>
            </div>
            <div>
              <label className={labelClasses}>Ders</label>
              <input type="text" value={course} onChange={(e) => setCourse(e.target.value)} placeholder="Örn: Biyoloji" className={inputClasses} required />
            </div>
          </div>

          <div>
            <label className={labelClasses}>Zorluk Seviyesi</label>
            <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
              {difficulties.map((diff) => (
                <button
                  key={diff.id}
                  type="button"
                  onClick={() => setDifficulty(diff.id)}
                  className={`py-4 rounded-xl font-black text-[10px] uppercase transition-all border-2 ${
                    difficulty === diff.id 
                      ? 'bg-notera-purple text-white border-notera-purple shadow-lg' 
                      : 'bg-white dark:bg-slate-800 border-slate-100 text-slate-500'
                  }`}
                >
                  {diff.label}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className={labelClasses}>Kazanım</label>
            <textarea value={outcome} onChange={(e) => setOutcome(e.target.value)} placeholder="Hangi beceriyi ölçmek istiyoruz?" className={`${inputClasses} min-h-[120px]`} required />
          </div>

          <button 
            type="submit" 
            disabled={isGenerating}
            className="w-full py-6 bg-notera-turquoise text-white rounded-2xl font-black text-sm tracking-[0.4em] uppercase shadow-lg hover:bg-notera-turquoise/90 transition-all disabled:opacity-50"
          >
            {isGenerating ? 'Examora Önerileri Hazırlıyor...' : 'İçeriği Oluştur'}
          </button>
        </form>
      </div>

      {generatedQuestions.length > 0 && (
        <div className="space-y-8 animate-fade-in">
          <h3 className="text-2xl font-black text-notera-purple dark:text-white uppercase px-6">Önerilen Taslaklar</h3>
          {generatedQuestions.map((q, idx) => (
            <div key={idx} className="bg-white dark:bg-slate-900 p-8 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-sm">
               <div className="flex justify-between items-start mb-4">
                  <span className="w-10 h-10 bg-notera-purple text-white rounded-xl flex items-center justify-center font-black">{idx + 1}</span>
                  <span className="px-3 py-1 bg-slate-100 rounded-lg text-[10px] font-black text-notera-purple">{q.maxScore} PUAN</span>
               </div>
               <p className="text-xl font-bold text-slate-800 dark:text-white mb-6 leading-relaxed">{q.text}</p>
               <div className="p-6 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border border-slate-100 dark:border-slate-700">
                  <span className="text-[10px] font-black text-notera-turquoise uppercase mb-2 block">İDEAL CEVAP TASLAĞI</span>
                  <p className="text-slate-600 text-sm">{q.expectedAnswer}</p>
               </div>
            </div>
          ))}
          <button 
            onClick={() => onQuestionsGenerated(generatedQuestions)}
            className="w-full py-8 bg-notera-purple text-white rounded-[2.5rem] font-black text-lg tracking-[0.2em] uppercase shadow-xl hover:bg-notera-purple/90"
          >
            Sınav Kağıdına Aktar
          </button>
        </div>
      )}
    </div>
  );
};

