import React, { useState } from 'react';
import { StudentSubmission, Exam, GradingResult, GradingStep } from '../types';

interface GradingDetailProps {
  submission: StudentSubmission;
  exam: Exam;
  onBack: () => void;
  onUpdate: (submission: StudentSubmission) => void;
}

const GradingDetail: React.FC<GradingDetailProps> = ({ submission, exam, onBack, onUpdate }) => {
  const [editedSubmission, setEditedSubmission] = useState(submission);
  const [approvedIds, setApprovedIds] = useState<Set<string>>(new Set());
  const [editingId, setEditingId] = useState<string | null>(null);

  const handleScoreChange = (qId: string, newScore: number) => {
    const max = exam.questions.find(q => q.id === qId)?.maxScore || 100;
    const score = Math.min(Math.max(0, newScore), max);
    const updatedResults = editedSubmission.results.map(r => r.questionId === qId ? { ...r, score } : r);
    setEditedSubmission({ ...editedSubmission, results: updatedResults, totalScore: updatedResults.reduce((a, b) => a + b.score, 0), status: 'reviewed' });
  };

  const approveQuestion = (qId: string) => {
    const newApproved = new Set(approvedIds);
    newApproved.add(qId);
    setApprovedIds(newApproved);
    setEditingId(null);
  };

  return (
    <div className="animate-fade-in pb-32">
      <div className="flex items-center justify-between mb-12 bg-notera-purple p-6 rounded-[2.5rem] shadow-xl sticky top-24 z-40">
        <button onClick={onBack} className="text-white font-black text-xs uppercase tracking-widest flex items-center gap-2">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
          Geri Dön
        </button>
        <h3 className="text-white font-black text-lg uppercase tracking-tight">{submission.studentName}</h3>
        <button onClick={() => { onUpdate(editedSubmission); onBack(); }} className="px-8 py-4 bg-notera-turquoise text-white rounded-2xl font-black text-xs uppercase shadow-lg">Notları Onayla</button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        <div className="lg:col-span-4">
          <div className="bg-white dark:bg-slate-900 p-8 rounded-[3rem] border border-slate-200 shadow-sm sticky top-52">
            <div className="aspect-[3/4] bg-slate-100 rounded-3xl overflow-hidden mb-6 border-4 border-slate-50">
              <img src={submission.imageUrl} alt="Exam" className="w-full h-full object-contain" />
            </div>
            <div className="text-center p-6 bg-slate-50 dark:bg-slate-800 rounded-3xl">
              <span className="text-[10px] font-black text-slate-400 uppercase block mb-1">Toplam Puan</span>
              <div className="text-6xl font-black text-notera-purple dark:text-notera-turquoise">{editedSubmission.totalScore}</div>
            </div>
          </div>
        </div>

        <div className="lg:col-span-8 space-y-8">
          {exam.questions.map((q, idx) => {
            const result = editedSubmission.results.find(r => r.questionId === q.id);
            if (!result) return null;
            const isApproved = approvedIds.has(q.id);

            return (
              <div key={q.id} className={`bg-white dark:bg-slate-900 rounded-[3rem] border-2 overflow-hidden transition-all ${isApproved ? 'border-notera-turquoise' : 'border-slate-100'}`}>
                <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-slate-50 dark:bg-slate-800/50">
                   <div className="flex items-center gap-4">
                      <span className="w-12 h-12 bg-notera-purple text-white rounded-xl flex items-center justify-center font-black">{idx + 1}</span>
                      <span className="text-[10px] font-black text-notera-turquoise uppercase">Soru Analizi</span>
                   </div>
                   <div className="flex items-center gap-4">
                      <input type="number" value={result.score} onChange={(e) => handleScoreChange(q.id, parseInt(e.target.value) || 0)} className="w-20 px-4 py-2 border-2 border-notera-purple rounded-xl text-center font-black text-2xl text-notera-purple outline-none" />
                      <span className="font-black text-slate-400">/ {q.maxScore}</span>
                      {!isApproved && <button onClick={() => approveQuestion(q.id)} className="p-2 bg-notera-turquoise text-white rounded-lg"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg></button>}
                   </div>
                </div>
                <div className="p-10 space-y-8">
                  <div>
                    <span className="text-[10px] font-black text-slate-400 uppercase mb-3 block">Öğrenci Yanıtı</span>
                    <p className="text-lg font-bold text-slate-900 dark:text-white italic border-l-4 border-notera-turquoise pl-6">"{result.extractedText}"</p>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="p-6 bg-slate-50 dark:bg-slate-800 rounded-3xl">
                      <span className="text-[10px] font-black text-notera-purple uppercase block mb-3">AI Değerlendirmesi</span>
                      <p className="text-sm font-bold text-slate-700 dark:text-slate-300">{result.reason}</p>
                    </div>
                    <div className="p-6 bg-notera-turquoise/10 rounded-3xl">
                      <span className="text-[10px] font-black text-notera-turquoise uppercase block mb-3">Gelişim Önerisi</span>
                      <p className="text-sm font-bold text-notera-purple italic">"{result.feedback}"</p>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

