        <p className="text-slate-500 font-bold text-lg">Analiz için sınav kağıtlarını yüklemeni bekliyorum.</p>
      </div>
    );
  }

  const averageScore = Math.round(submissions.reduce((a, b) => a + b.totalScore, 0) / (submissions.length || 1));

  return (
    <div className="animate-fade-in pb-20">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12">
        <div>
          <h2 className="text-5xl font-black text-notera-purple dark:text-white uppercase tracking-tighter leading-none mb-4">EduMetrik <span className="text-notera-turquoise">Merkezi</span></h2>
