          </p>
        </div>
        <div className="flex gap-4">
          <button onClick={onViewAnalytics} className="px-8 py-4 bg-notera-turquoise text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg hover:shadow-xl transition-all">Analiz Raporu</button>
