        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
        {[
          { label: 'Sınıf Ortalaması', val: averageScore, color: 'text-notera-purple' },
          { label: 'Kazanım Uyumu', val: `%${Math.round((submissions.filter(s => s.totalScore >= 50).length / submissions.length) * 100)}`, color: 'text-notera-turquoise' },
