import React, { useState, useEffect } from 'react';
import { Exam, StudentSubmission, Question, UserSettings, FeedbackTone } from './types';
import Header from './components/Header';
import Footer from './components/Footer';
import ExamSetup from './components/ExamSetup';
import UploadSection from './components/UploadSection';
import GradingDashboard from './components/GradingDashboard';
import GradingDetail from './components/GradingDetail';
import AnalyticsView from './components/AnalyticsView';
import QuestionPrep from './components/QuestionPrep';
import SettingsPanel from './components/SettingsPanel';
import ExamPaper from './components/ExamPaper';
import AboutView from './components/AboutView';
import HomePanel from './components/HomePanel';
import AdminPanel from './components/AdminPanel';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'home' | 'setup' | 'upload' | 'dashboard' | 'detail' | 'analytics' | 'question-prep' | 'settings' | 'exam-paper' | 'info' | 'admin' | 'admin-login'>('info');
  const [exam, setExam] = useState<Exam | null>(null);
  const [submissions, setSubmissions] = useState<StudentSubmission[]>([]);
  const [selectedSubmissionId, setSelectedSubmissionId] = useState<string | null>(null);
  const [prefilledQuestions, setPrefilledQuestions] = useState<Question[]>([]);
  const [settings, setSettings] = useState<UserSettings>({
    teacherName: '',
    schoolName: '',
    subject: '',
    theme: 'light',
    aiSensitivity: 'normal',
    feedbackTone: 'encouraging',
    analyticsLevel: 'basic'
  });

  const [adminPassword, setAdminPassword] = useState("");
  const [adminError, setAdminError] = useState(false);

  useEffect(() => {
    const savedExam = localStorage.getItem('notera_exam');
    const savedSubmissions = localStorage.getItem('notera_submissions');
    const savedSettings = localStorage.getItem('notera_settings');

    if (savedExam) setExam(JSON.parse(savedExam));
    if (savedSubmissions) setSubmissions(JSON.parse(savedSubmissions));
    if (savedSettings) {
      const parsedSettings = JSON.parse(savedSettings);
      setSettings({
        ...parsedSettings,
        analyticsLevel: parsedSettings.analyticsLevel || 'basic'
      });
      applyTheme(parsedSettings.theme);
    }

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.shiftKey && e.altKey && e.code === 'KeyA') {
        setCurrentView('admin-login');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleAdminAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === "admin123") {
      setCurrentView('admin');
      setAdminError(false);
      setAdminPassword("");
      window.scrollTo(0, 0);
    } else {
      setAdminError(true);
    }
  };

  const applyTheme = (theme: 'dark' | 'light' | 'system') => {
    const root = window.document.documentElement;
    if (theme === 'dark' || (theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  };

  const saveToLocal = (updatedExam: Exam | null, updatedSubmissions: StudentSubmission[]) => {
    if (updatedExam) localStorage.setItem('notera_exam', JSON.stringify(updatedExam));
    localStorage.setItem('notera_submissions', JSON.stringify(updatedSubmissions));
  };

  const handleSettingsUpdate = (newSettings: UserSettings) => {
    setSettings(newSettings);
    localStorage.setItem('notera_settings', JSON.stringify(newSettings));
    applyTheme(newSettings.theme);
  };

  const handleExamSaved = (newExam: Exam) => {
    setExam(newExam);
    saveToLocal(newExam, submissions);
    setCurrentView('exam-paper');
  };

  const handleUploadComplete = (newSubmissions: StudentSubmission[]) => {
    const updated = [...submissions, ...newSubmissions];
    setSubmissions(updated);
    saveToLocal(exam, updated);
    setCurrentView('dashboard');
  };

  const handleSubmissionUpdate = (updatedSub: StudentSubmission) => {
    const updated = submissions.map(s => s.id === updatedSub.id ? updatedSub : s);
    setSubmissions(updated);
    saveToLocal(exam, updated);
  };

  const handleQuestionsGenerated = (questions: Question[]) => {
    setPrefilledQuestions(questions);
    setCurrentView('setup');
  };

  const renderView = () => {
    switch (currentView) {
      case 'info': return <AboutView onStart={() => setCurrentView('home')} />;
      case 'home': return <HomePanel onNavigate={(view) => setCurrentView(view)} isExamSet={!!exam} hasSubmissions={submissions.length > 0} />;
      case 'settings': return <SettingsPanel settings={settings} onUpdate={handleSettingsUpdate} onResetAll={() => { localStorage.clear(); window.location.reload(); }} />;
      case 'question-prep': return <QuestionPrep onQuestionsGenerated={handleQuestionsGenerated} />;
      case 'setup': return <ExamSetup initialExam={exam} onSave={handleExamSaved} prefilledQuestions={prefilledQuestions} />;
      case 'exam-paper': return exam ? <ExamPaper exam={exam} settings={settings} onBack={() => setCurrentView('setup')} onStartGrading={() => setCurrentView('upload')} /> : null;
      case 'upload': return <UploadSection onUpload={handleUploadComplete} exam={exam!} settings={settings} />;
      case 'dashboard': return <GradingDashboard submissions={submissions} settings={settings} onSelect={(id) => { setSelectedSubmissionId(id); setCurrentView('detail'); }} onReset={() => { setSubmissions([]); saveToLocal(exam, []); }} onViewAnalytics={() => setCurrentView('analytics')} />;
      case 'detail':
        const sub = submissions.find(s => s.id === selectedSubmissionId);
        return sub ? <GradingDetail submission={sub} exam={exam!} onBack={() => setCurrentView('dashboard')} onUpdate={handleSubmissionUpdate} /> : null;
      case 'analytics': return <AnalyticsView submissions={submissions} exam={exam!} settings={settings} onBack={() => setCurrentView('dashboard')} />;
      case 'admin': return <AdminPanel />;
      case 'admin-login': return (
        <div className="min-h-[60vh] flex items-center justify-center animate-fade-in">
          <div className="bg-white dark:bg-slate-900 p-12 rounded-[3rem] border border-slate-200 dark:border-slate-800 shadow-2xl w-full max-w-md text-center">
            <div className="w-16 h-16 bg-notera-purple/10 text-notera-purple rounded-2xl flex items-center justify-center mx-auto mb-6">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
            </div>
            <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter mb-2">Yönetici Girişi</h2>
            <p className="text-slate-500 text-sm font-bold mb-8 uppercase tracking-widest italic">Devam etmek için şifre girin</p>

            <form onSubmit={handleAdminAuth} className="space-y-4">
              <input 
                type="password" 
                value={adminPassword}
                onChange={(e) => setAdminPassword(e.target.value)}
                placeholder="Şifre (admin123)"
                className={`w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border-2 rounded-2xl outline-none font-black text-center text-xl transition-all ${adminError ? 'border-rose-500 bg-rose-50' : 'border-transparent focus:border-notera-purple'}`}
                autoFocus
              />
              {adminError && <p className="text-rose-500 text-[10px] font-black uppercase tracking-widest">Hatalı şifre, tekrar deneyin.</p>}
              <button type="submit" className="w-full py-5 bg-notera-purple text-white rounded-2xl font-black uppercase tracking-widest shadow-xl hover:scale-[1.02] active:scale-95 transition-all">Giriş Yap</button>
              <button type="button" onClick={() => setCurrentView('home')} className="w-full text-slate-400 font-black text-[10px] uppercase tracking-widest hover:text-slate-600 transition-colors">İptal Et</button>
            </form>
          </div>
        </div>
      );
      default: return <HomePanel onNavigate={(view) => setCurrentView(view)} isExamSet={!!exam} hasSubmissions={submissions.length > 0} />;
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-300 ${settings.theme === 'dark' ? 'bg-notera-dark text-slate-100' : 'bg-notera-gray text-slate-900'}`}>
      <Header currentView={currentView} onNavigate={(view) => setCurrentView(view)} isExamSet={!!exam} />
      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        {renderView()}
      </main>
      <Footer onAdminClick={() => setCurrentView('admin-login')} onNavigate={setCurrentView} />
    </div>
  );
};

export default App;

import React from 'react';
import { StudentSubmission, UserSettings } from '../types';

interface GradingDashboardProps {
  submissions: StudentSubmission[];
  settings: UserSettings;
  onSelect: (id: string) => void;
  onReset: () => void;
  onViewAnalytics: () => void;
}

const GradingDashboard: React.FC<GradingDashboardProps> = ({ submissions, settings, onSelect, onReset, onViewAnalytics }) => {
  if (submissions.length === 0) {
    return (
      <div className="py-40 text-center animate-pulse space-y-6">
        <h3 className="text-4xl font-black text-notera-purple dark:text-white uppercase tracking-tighter">EduMetrik Hazır</h3>
        <p className="text-slate-500 font-bold text-xl">Değerlendirme için kağıtları yüklemeni bekliyorum.</p>
      </div>
    );
  }

  const averageScore = Math.round(submissions.reduce((a, b) => a + b.totalScore, 0) / (submissions.length || 1));
  const needsReviewCount = submissions.filter(s => s.results.some(r => r.confidence < 0.6)).length;

  const level = settings.analyticsLevel || 'basic';

  const stats = [
    { label: 'Sınıf Ortalaması', val: averageScore, color: 'text-notera-purple', visible: true },
    { label: 'Başarı Oranı', val: `%${Math.round((submissions.filter(s => s.totalScore >= 50).length / submissions.length) * 100)}`, color: 'text-notera-turquoise', visible: level !== 'basic' },
    { label: 'Destek Bekleyen', val: submissions.filter(s => s.totalScore < 50).length, color: 'text-rose-500', visible: level !== 'basic' },
    { label: 'Şüpheli Okuma', val: needsReviewCount, color: 'text-amber-500', visible: level === 'institutional' }
  ];

  return (
    <div className="animate-fade-in pb-32">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 mb-16">
        <div className="space-y-3">
          <h2 className="text-5xl font-black text-notera-purple dark:text-white uppercase tracking-tighter leading-none">EduMetrik Analizi</h2>
          <div className="flex items-center gap-3">
            <p className="text-slate-400 font-bold text-xl uppercase tracking-widest">
              {submissions.length} Kağıt Değerlendirildi
            </p>
            <span className="px-3 py-1 bg-indigo-50 dark:bg-indigo-900/30 rounded-lg text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase border border-indigo-100 dark:border-indigo-900/50">
              {level.toUpperCase()} ANALİZ
            </span>
          </div>
        </div>
        <div className="flex gap-4">
          <button onClick={onViewAnalytics} className="px-10 py-5 bg-notera-turquoise text-white rounded-[1.5rem] font-black text-xs uppercase tracking-widest shadow-xl">Analiz Raporu</button>
          <button onClick={onReset} className="px-10 py-5 bg-white text-slate-500 rounded-[1.5rem] font-black text-xs uppercase tracking-widest border border-slate-200">Temizle</button>
        </div>
      </div>

      {needsReviewCount > 0 && level === 'institutional' && (
        <div className="mb-12 p-6 bg-amber-50 dark:bg-amber-950/20 border-2 border-amber-200 dark:border-amber-900/50 rounded-[2rem] flex items-center gap-6 animate-pulse">
          <div className="text-4xl">⚠️</div>
          <div>
            <h4 className="font-black text-amber-900 dark:text-amber-400 uppercase tracking-tight">AI Şüpheli Okumalar Tespit Etti</h4>
            <p className="text-amber-700 dark:text-amber-500 font-bold text-sm">{needsReviewCount} öğrencinin kağıdında el yazısı tam anlaşılamamış olabilir. Bu kağıtları manuel kontrol etmenizi öneririz.</p>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 mb-16">
        {stats.filter(s => s.visible).map((stat, i) => (
          <div key={i} className="bg-white dark:bg-slate-900 p-10 rounded-[3rem] border border-slate-100 dark:border-slate-800 shadow-sm transition-all hover:shadow-xl group">
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-4">{stat.label}</span>
            <div className={`text-6xl font-black ${stat.color} tracking-tighter`}>{stat.val}</div>
          </div>
        ))}
        {level === 'basic' && (
          <div className="bg-slate-50 dark:bg-slate-800/30 p-10 rounded-[3rem] border border-dashed border-slate-200 dark:border-slate-800 flex flex-col justify-center items-center text-center opacity-60">
             <span className="text-[10px] font-black text-slate-400 uppercase mb-2">GELİŞMİŞ VERİLER</span>
             <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">KİLİTLİ (ADVANCED GEREKİR)</p>
          </div>
        )}
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[3.5rem] border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 dark:bg-slate-800/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
            <tr>
              <th className="px-12 py-6">Öğrenci</th>
              <th className="px-12 py-6">Puan</th>
              <th className="px-12 py-6">Durum</th>
              <th className="px-12 py-6 text-right">Aksiyon</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
            {submissions.map((sub) => {
              const isLowConfidence = sub.results.some(r => r.confidence < 0.6);
              return (
                <tr key={sub.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-all">
                  <td className="px-12 py-10">
                    <div className="font-black text-slate-900 dark:text-white text-xl tracking-tight flex items-center gap-3">
                      {sub.studentName}
                      {isLowConfidence && level === 'institutional' && <span className="px-3 py-1 bg-amber-100 text-amber-700 rounded-lg text-[9px] font-black uppercase tracking-widest">AI ŞÜPHELİ</span>}
                    </div>
                  </td>
                  <td className="px-12 py-10">
                    <span className="text-4xl font-black text-notera-purple dark:text-notera-turquoise">{sub.totalScore}</span>
                  </td>
                  <td className="px-12 py-10">
                     <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${sub.totalScore >= 50 ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                      {sub.totalScore >= 50 ? 'GEÇTİ' : 'KALDI'}
                    </span>
                  </td>
                  <td className="px-12 py-10 text-right">
                    <button onClick={() => onSelect(sub.id)} className="px-8 py-3 bg-white dark:bg-slate-800 border-2 border-slate-200 rounded-2xl text-[10px] font-black text-notera-purple uppercase tracking-widest transition-all shadow-sm">İncele</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default GradingDashboard;

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { StudentSubmission, Exam, UserSettings } from '../types';

interface AnalyticsViewProps {
  submissions: StudentSubmission[];
  exam: Exam;
  settings: UserSettings;
  onBack: () => void;
}

const AnalyticsView: React.FC<AnalyticsViewProps> = ({ submissions, exam, settings, onBack }) => {
  const level = settings.analyticsLevel || 'basic';

  const successData = useMemo(() => {
    const successful = submissions.filter(s => s.totalScore >= 50).length;
    const unsuccessful = submissions.length - successful;
    return [
      { name: 'Başarılı', value: successful, color: '#4FB6B2' },
      { name: 'Başarısız', value: unsuccessful, color: '#f43f5e' }
    ];
  }, [submissions]);

  const chartData = useMemo(() => {
    return exam.questions.map((q, idx) => {
      const scores = submissions.map(s => {
        const res = s.results.find(r => r.questionId === q.id);
        return res ? (res.score / q.maxScore) * 100 : 0;
      });
      const avg = scores.reduce((a, b) => a + b, 0) / (scores.length || 1);
      return { name: `Soru ${idx + 1}`, başarı: Math.round(avg) };
    });
  }, [submissions, exam]);

  const averageScore = Math.round(submissions.reduce((a, b) => a + b.totalScore, 0) / (submissions.length || 1));

  const exportToCSV = () => {
    if (level === 'basic') return;
    const headers = ["Öğrenci Adı", "Toplam Puan", "Durum"];
    const rows = submissions.map(s => [s.studentName, s.totalScore, s.totalScore >= 50 ? "Geçti" : "Kaldı"]);
    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers.join(","), ...rows.map(r => r.join(","))].join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `${exam.courseName}_Not_Listesi.csv`);
    document.body.appendChild(link);
    link.click();
  };

  return (
    <div className="animate-fade-in pb-24 max-w-6xl mx-auto">
      <div className="flex items-center justify-between mb-10 bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl no-print">
        <div className="flex items-center gap-6">
          <button onClick={onBack} className="w-12 h-12 flex items-center justify-center bg-indigo-600 text-white rounded-2xl">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
          </button>
          <div className="space-y-1">
            <h2 className="text-3xl font-black text-white uppercase tracking-tighter">{exam.courseName} - ANALİZ</h2>
            <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.4em]">{level} sürüm raporu</span>
          </div>
        </div>
        <div className="flex gap-4">
          {level !== 'basic' && (
            <button onClick={exportToCSV} className="px-8 py-4 bg-notera-turquoise text-white rounded-2xl font-black text-xs uppercase tracking-widest transition-all shadow-xl flex items-center gap-2">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
               EXCEL (CSV) AKTAR
            </button>
          )}
          {level === 'institutional' && (
            <button onClick={() => window.print()} className="px-8 py-4 bg-white text-slate-900 rounded-2xl font-black text-xs uppercase shadow-xl">PDF RAPORU</button>
          )}
          {level === 'basic' && (
            <div className="px-6 py-4 bg-slate-800 text-slate-400 rounded-2xl font-black text-[9px] uppercase tracking-widest flex items-center gap-2">
              <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" /></svg>
              PDF & EXCEL KİLİTLİ
            </div>
          )}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-12">
        <div className="lg:col-span-1 bg-white dark:bg-slate-900 rounded-[3rem] p-10 shadow-xl text-center border border-slate-100 dark:border-slate-800">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-10">BAŞARI DAĞILIMI</h3>
            <div className="h-48 mb-10">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={successData} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                    {successData.map((entry, index) => (<Cell key={`cell-${index}`} fill={entry.color} />))}
                  </Pie>
                  <Tooltip contentStyle={{borderRadius: '1rem', border: 'none'}} />
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div className="text-6xl font-black text-notera-purple dark:text-white tracking-tighter">{averageScore}</div>
            <div className="text-[10px] font-black text-notera-turquoise uppercase mt-2">SINIF ORTALAMASI</div>
        </div>

        <div className="lg:col-span-2 bg-white dark:bg-slate-900 rounded-[3rem] p-10 shadow-xl border border-slate-100 dark:border-slate-800">
          <div className="flex justify-between items-center mb-10">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">SORU BAZLI ANALİZ (%)</h3>
            {level === 'basic' && <span className="text-[9px] font-black text-rose-400 uppercase">Önizleme Modu</span>}
          </div>
          <div className={`h-64 ${level === 'basic' ? 'blur-sm grayscale pointer-events-none' : ''}`}>
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f910" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11, fontWeight: 900}} />
                <YAxis axisLine={false} tickLine={false} unit="%" tick={{fill: '#94a3b8', fontSize: 10}} />
                <Tooltip contentStyle={{borderRadius: '1rem', border: 'none'}} />
                <Bar dataKey="başarı" radius={[10, 10, 0, 0]} barSize={40}>
                  {chartData.map((entry, index) => (<Cell key={`cell-${index}`} fill={entry.başarı >= 50 ? '#4FB6B2' : '#f43f5e'} />))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
          {level === 'basic' && (
            <div className="mt-8 p-6 bg-indigo-50 dark:bg-indigo-900/10 rounded-2xl text-center">
              <p className="text-xs font-bold text-indigo-600 dark:text-indigo-400">Soru bazlı başarı analizini görmek için <span className="font-black">ADVANCED</span> plana yükseltin.</p>
            </div>
          )}
        </div>
      </div>

      {level === 'institutional' && (
        <div className="bg-white dark:bg-slate-900 rounded-[3rem] p-10 shadow-xl border border-slate-100 dark:border-slate-800 animate-slide-up">
           <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">OKUL GENELİ KARŞILAŞTIRMA (SİMÜLASYON)</h3>
           <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {[
                { label: 'Zümre Sıralaması', val: '2 / 8', desc: 'Biyoloji öğretmenleri arasında' },
                { label: 'Okul Ortalaması Sapması', val: '+12.4', desc: 'Genel ortalamanın üzerinde' },
                { label: 'Kazanım Tamamlama', val: '%88', desc: 'Hücre ünitesi hedefi' }
              ].map((m, i) => (
                <div key={i} className="p-6 bg-slate-50 dark:bg-slate-800/50 rounded-2xl">
                  <div className="text-2xl font-black text-notera-purple dark:text-notera-turquoise mb-1">{m.val}</div>
                  <div className="text-[10px] font-black text-slate-900 dark:text-white uppercase mb-1">{m.label}</div>
                  <div className="text-[9px] font-bold text-slate-400">{m.desc}</div>
                </div>
              ))}
           </div>
        </div>
      )}
    </div>
  );
};

export default AnalyticsView;

import React from 'react';
import { UserSettings, FeedbackTone, AnalyticsLevel } from '../types';

interface SettingsPanelProps {
  settings: UserSettings;
  onUpdate: (settings: UserSettings) => void;
  onResetAll: () => void;
}

const SettingsPanel: React.FC<SettingsPanelProps> = ({ settings, onUpdate, onResetAll }) => {
  const handleChange = (field: keyof UserSettings, value: any) => {
    onUpdate({ ...settings, [field]: value });
  };

  const inputClasses = "w-full px-5 py-4 bg-white dark:bg-slate-900 border-2 border-slate-200 dark:border-slate-800 rounded-[1rem] focus:ring-4 focus:ring-indigo-600/20 focus:border-indigo-600 outline-none transition-all text-indigo-950 dark:text-indigo-100 font-bold text-lg";
  const labelClasses = "block text-[11px] font-black text-slate-500 dark:text-indigo-400 mb-3 uppercase tracking-[0.25em]";

  return (
    <div className="animate-fade-in max-w-4xl mx-auto pb-20">
      <div className="mb-12 p-8 bg-white dark:bg-slate-900 border-l-8 border-notera-purple rounded-[2.5rem] shadow-xl border border-slate-200 dark:border-slate-800">
        <h2 className="text-4xl font-black text-slate-900 dark:text-white uppercase tracking-tighter leading-none mb-4">Ayarlar & Profil</h2>
        <p className="text-slate-500 dark:text-indigo-400 font-bold text-lg">Platform deneyiminizi ve AI hassasiyetini özelleştirin.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* KULLANICI BİLGİLERİ */}
        <div className="bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-xl space-y-8">
           <h3 className="font-black text-slate-900 dark:text-white uppercase tracking-widest text-xs">Eğitmen Profili</h3>
          <div>
            <label className={labelClasses}>Ad Soyad</label>
            <input type="text" value={settings.teacherName} onChange={(e) => handleChange('teacherName', e.target.value)} className={inputClasses} />
          </div>
          <div>
            <label className={labelClasses}>Okul / Kurum</label>
            <input type="text" value={settings.schoolName} onChange={(e) => handleChange('schoolName', e.target.value)} className={inputClasses} />
          </div>

          <div className="pt-4 border-t border-slate-100 dark:border-slate-800">
            <h3 className="font-black text-slate-900 dark:text-white uppercase tracking-widest text-xs mb-6">EduMetrik Paket Seçimi</h3>
            <div className="space-y-3">
              {(['basic', 'advanced', 'institutional'] as const).map((lvl) => (
                <button
                  key={lvl}
                  onClick={() => handleChange('analyticsLevel', lvl)}
                  className={`w-full flex items-center justify-between p-4 rounded-xl border-2 transition-all ${settings.analyticsLevel === lvl ? 'bg-indigo-600 border-indigo-500 text-white' : 'bg-slate-50 dark:bg-slate-800 border-transparent text-slate-500'}`}
                >
                  <span className="font-black text-[10px] uppercase tracking-widest">{lvl} ANALİZ</span>
                  {settings.analyticsLevel === lvl && <span>✓</span>}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="space-y-8">
          {/* AI GERİ BİLDİRİM TONU */}
          <div className="bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-xl">
             <h3 className="font-black text-slate-900 dark:text-white uppercase tracking-widest text-xs mb-6">AI Geri Bildirim Tonu</h3>
             <div className="grid grid-cols-1 gap-3">
              {[
                { id: 'encouraging', label: 'Teşvik Edici (Önerilen)', icon: '🌟' },
                { id: 'academic', label: 'Akademik & Ciddi', icon: '🎓' },
                { id: 'concise', label: 'Kısa & Öz', icon: '⚡' }
              ].map(t => (
                <button
                  key={t.id}
                  onClick={() => handleChange('feedbackTone', t.id as FeedbackTone)}
                  className={`flex items-center gap-4 p-5 rounded-2xl border-2 transition-all ${settings.feedbackTone === t.id ? 'bg-notera-purple border-notera-purple text-white shadow-lg' : 'bg-slate-50 dark:bg-slate-800 border-transparent text-slate-500'}`}
                >
                  <span className="text-2xl">{t.icon}</span>
                  <span className="font-black text-[10px] uppercase tracking-widest">{t.label}</span>
                </button>
              ))}
             </div>
          </div>

          {/* TEMA SEÇİMİ */}
          <div className="bg-white dark:bg-slate-900 p-10 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-xl">
            <h3 className="font-black text-slate-900 dark:text-white uppercase tracking-widest text-xs mb-6">Görünüm Modu</h3>
            <div className="flex gap-4">
              {(['dark', 'light', 'system'] as const).map((t) => (
                <button key={t} onClick={() => handleChange('theme', t)} className={`flex-1 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all border-2 ${settings.theme === t ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg' : 'bg-slate-50 dark:bg-slate-800 border-transparent text-slate-500'}`}>{t}</button>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="mt-12 bg-rose-50 dark:bg-rose-900/10 p-10 rounded-[2.5rem] border-2 border-dashed border-rose-200">
        <button onClick={onResetAll} className="w-full py-5 bg-rose-600 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em]">TÜM VERİLERİ SIFIRLA</button>
      </div>
    </div>
  );
};

export default SettingsPanel;

export interface GradingStep {
  text: string;
  score: number;
}

export interface Question {
  id: string;
  text: string;
  expectedAnswer: string;
  keywords: string[];
  maxScore: number;
  gradingSteps?: GradingStep[];
  options?: string[];
}

export interface Exam {
  id: string;
  type: 'open-ended' | 'multiple-choice';
  classSection: string;
  courseName: string;
  examName: string;
  date: string;
  questions: Question[];
}

export interface GradingResult {
  questionId: string;
  extractedText: string;
  selectedOption?: string;
  score: number;
  reason: string;
  feedback: string;
  confidence: number;
}

export interface StudentSubmission {
  id: string;
  studentName: string;
  imageUrl: string;
  base64Data: string;
  status: 'pending' | 'processing' | 'graded' | 'reviewed';
  results: GradingResult[];
  totalScore: number;
}

export type FeedbackTone = 'encouraging' | 'academic' | 'concise';

export type AnalyticsLevel = 'basic' | 'advanced' | 'institutional';

export interface UserSettings {
  teacherName: string;
  schoolName: string;
  subject: string;
  theme: 'dark' | 'light' | 'system';
  aiSensitivity: 'low' | 'normal' | 'strict';
  feedbackTone: FeedbackTone;
  isPremium?: boolean;
  analyticsLevel: AnalyticsLevel;
}

// ADMIN & PAYMENT TYPES
export interface PricingPlan {
  id: string;
  name: string;
  price: number;
  currency: string;
  paperLimit: number;
  questionGenLimit: number;
  analyticsLevel: AnalyticsLevel;
  features: string[];
  isPopular?: boolean;
  color: string;
}

export interface Campaign {
  id: string;
  code: string;
  discount: number;
  expiryDate: string;
  isActive: boolean;
  usageCount: number;
}

export interface AdminUser {
  id: string;
  name: string;
  email: string;
  school: string;
  planId: string;
  joinedAt: string;
  status: 'active' | 'suspended' | 'pending';
  totalPapersRead: number;
}

export interface AdminStats {
  totalRevenue: number;
  activeUsers: number;
  processedPapers: number;
  conversions: number;
  growthData: { date: string; users: number; revenue: number; papers: number }[];
  moduleUsage: { module: string; usage: number; color: string }[];
}

import React, { useState, useEffect } from 'react';
import { Exam, StudentSubmission, Question, UserSettings, PricingPlan } from './types';
import Header from './components/Header';
import Footer from './components/Footer';
import ExamSetup from './components/ExamSetup';
import UploadSection from './components/UploadSection';
import GradingDashboard from './components/GradingDashboard';
import GradingDetail from './components/GradingDetail';
import AnalyticsView from './components/AnalyticsView';
import QuestionPrep from './components/QuestionPrep';
import SettingsPanel from './components/SettingsPanel';
import ExamPaper from './components/ExamPaper';
import AboutView from './components/AboutView';
import HomePanel from './components/HomePanel';
import AdminPanel from './components/AdminPanel';
import PricingView from './components/PricingView';
import CheckoutView from './components/CheckoutView';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'home' | 'setup' | 'upload' | 'dashboard' | 'detail' | 'analytics' | 'question-prep' | 'settings' | 'exam-paper' | 'info' | 'admin' | 'admin-login' | 'pricing' | 'checkout'>('info');
  const [exam, setExam] = useState<Exam | null>(null);
  const [submissions, setSubmissions] = useState<StudentSubmission[]>([]);
  const [selectedSubmissionId, setSelectedSubmissionId] = useState<string | null>(null);
  const [selectedPlan, setSelectedPlan] = useState<PricingPlan | null>(null);
  const [prefilledQuestions, setPrefilledQuestions] = useState<Question[]>([]);
  const [settings, setSettings] = useState<UserSettings>({
    teacherName: '',
    schoolName: '',
    subject: '',
    theme: 'light',
    aiSensitivity: 'normal',
    feedbackTone: 'encouraging',
    analyticsLevel: 'basic'
  });

  const [adminPassword, setAdminPassword] = useState("");
  const [adminError, setAdminError] = useState(false);

  useEffect(() => {
    const savedExam = localStorage.getItem('notera_exam');
    const savedSubmissions = localStorage.getItem('notera_submissions');
    const savedSettings = localStorage.getItem('notera_settings');

    if (savedExam) setExam(JSON.parse(savedExam));
    if (savedSubmissions) setSubmissions(JSON.parse(savedSubmissions));
    if (savedSettings) {
      const parsedSettings = JSON.parse(savedSettings);
      setSettings({
        ...parsedSettings,
        analyticsLevel: parsedSettings.analyticsLevel || 'basic'
      });
      applyTheme(parsedSettings.theme);
    }

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.shiftKey && e.altKey && e.code === 'KeyA') {
        setCurrentView('admin-login');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleAdminAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === "admin123") {
      setCurrentView('admin');
      setAdminError(false);
      setAdminPassword("");
      window.scrollTo(0, 0);
    } else {
      setAdminError(true);
    }
  };

  const applyTheme = (theme: 'dark' | 'light' | 'system') => {
    const root = window.document.documentElement;
    if (theme === 'dark' || (theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  };

  const saveToLocal = (updatedExam: Exam | null, updatedSubmissions: StudentSubmission[]) => {
    if (updatedExam) localStorage.setItem('notera_exam', JSON.stringify(updatedExam));
    localStorage.setItem('notera_submissions', JSON.stringify(updatedSubmissions));
  };

  const handleSettingsUpdate = (newSettings: UserSettings) => {
    setSettings(newSettings);
    localStorage.setItem('notera_settings', JSON.stringify(newSettings));
    applyTheme(newSettings.theme);
  };

  const handleExamSaved = (newExam: Exam) => {
    setExam(newExam);
    saveToLocal(newExam, submissions);
    setCurrentView('exam-paper');
  };

  const handleUploadComplete = (newSubmissions: StudentSubmission[]) => {
    const updated = [...submissions, ...newSubmissions];
    setSubmissions(updated);
    saveToLocal(exam, updated);
    setCurrentView('dashboard');
  };

  const handleSubmissionUpdate = (updatedSub: StudentSubmission) => {
    const updated = submissions.map(s => s.id === updatedSub.id ? updatedSub : s);
    setSubmissions(updated);
    saveToLocal(exam, updated);
  };

  const handleQuestionsGenerated = (questions: Question[]) => {
    setPrefilledQuestions(questions);
    setCurrentView('setup');
  };

  const handlePlanSelection = (plan: PricingPlan) => {
    if (plan.price === 0) {
      setSettings({ ...settings, isPremium: false, analyticsLevel: 'basic' });
      setCurrentView('home');
    } else {
      setSelectedPlan(plan);
      setCurrentView('checkout');
    }
  };

  const handlePaymentSuccess = () => {
    if (selectedPlan) {
      const newSettings: UserSettings = {
        ...settings,
        isPremium: true,
        analyticsLevel: selectedPlan.analyticsLevel
      };
      setSettings(newSettings);
      localStorage.setItem('notera_settings', JSON.stringify(newSettings));
      setCurrentView('home');
      alert(`Tebrikler! ${selectedPlan.name} planına başarıyla geçtiniz.`);
    }
  };

  const renderView = () => {
    switch (currentView) {
      case 'info': return <AboutView onStart={() => setCurrentView('pricing')} />;
      case 'pricing': return <PricingView onSelectPlan={handlePlanSelection} />;
      case 'checkout': return selectedPlan ? <CheckoutView plan={selectedPlan} onCancel={() => setCurrentView('pricing')} onSuccess={handlePaymentSuccess} /> : null;
      case 'home': return <HomePanel onNavigate={(view) => setCurrentView(view)} isExamSet={!!exam} hasSubmissions={submissions.length > 0} />;
      case 'settings': return <SettingsPanel settings={settings} onUpdate={handleSettingsUpdate} onResetAll={() => { localStorage.clear(); window.location.reload(); }} />;
      case 'question-prep': return <QuestionPrep onQuestionsGenerated={handleQuestionsGenerated} />;
      case 'setup': return <ExamSetup initialExam={exam} onSave={handleExamSaved} prefilledQuestions={prefilledQuestions} />;
      case 'exam-paper': return exam ? <ExamPaper exam={exam} settings={settings} onBack={() => setCurrentView('setup')} onStartGrading={() => setCurrentView('upload')} /> : null;
      case 'upload': return <UploadSection onUpload={handleUploadComplete} exam={exam!} settings={settings} />;
      case 'dashboard': return <GradingDashboard submissions={submissions} settings={settings} onSelect={(id) => { setSelectedSubmissionId(id); setCurrentView('detail'); }} onReset={() => { setSubmissions([]); saveToLocal(exam, []); }} onViewAnalytics={() => setCurrentView('analytics')} />;
      case 'detail':
        const sub = submissions.find(s => s.id === selectedSubmissionId);
        return sub ? <GradingDetail submission={sub} exam={exam!} onBack={() => setCurrentView('dashboard')} onUpdate={handleSubmissionUpdate} /> : null;
      case 'analytics': return <AnalyticsView submissions={submissions} exam={exam!} settings={settings} onBack={() => setCurrentView('dashboard')} />;
      case 'admin': return <AdminPanel />;
      case 'admin-login': return (
        <div className="min-h-[60vh] flex items-center justify-center animate-fade-in">
          <div className="bg-white dark:bg-slate-900 p-12 rounded-[3rem] border border-slate-200 dark:border-slate-800 shadow-2xl w-full max-w-md text-center">
            <div className="w-16 h-16 bg-notera-purple/10 text-notera-purple rounded-2xl flex items-center justify-center mx-auto mb-6">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
            </div>
            <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter mb-2">Yönetici Girişi</h2>
            <p className="text-slate-500 text-sm font-bold mb-8 uppercase tracking-widest italic">Devam etmek için şifre girin</p>

            <form onSubmit={handleAdminAuth} className="space-y-4">
              <input 
                type="password" 
                value={adminPassword}
                onChange={(e) => setAdminPassword(e.target.value)}
                placeholder="Şifre (admin123)"
                className={`w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border-2 rounded-2xl outline-none font-black text-center text-xl transition-all ${adminError ? 'border-rose-500 bg-rose-50' : 'border-transparent focus:border-notera-purple'}`}
                autoFocus
              />
              {adminError && <p className="text-rose-500 text-[10px] font-black uppercase tracking-widest">Hatalı şifre, tekrar deneyin.</p>}
              <button type="submit" className="w-full py-5 bg-notera-purple text-white rounded-2xl font-black uppercase tracking-widest shadow-xl hover:scale-[1.02] active:scale-95 transition-all">Giriş Yap</button>
              <button type="button" onClick={() => setCurrentView('home')} className="w-full text-slate-400 font-black text-[10px] uppercase tracking-widest hover:text-slate-600 transition-colors">İptal Et</button>
            </form>
          </div>
        </div>
      );
      default: return <HomePanel onNavigate={(view) => setCurrentView(view)} isExamSet={!!exam} hasSubmissions={submissions.length > 0} />;
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-300 ${settings.theme === 'dark' ? 'bg-notera-dark text-slate-100' : 'bg-notera-gray text-slate-900'}`}>
      <Header currentView={currentView} onNavigate={(view) => setCurrentView(view)} isExamSet={!!exam} />
      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        {renderView()}
      </main>
      <Footer onAdminClick={() => setCurrentView('admin-login')} onNavigate={setCurrentView} />
    </div>
  );
};

export default App;

