    öğrencinin bilgisini derinlemesine ölçen profesyonel açık uçlu sınav soruları hazırlarsın.
    Sorular MEB müfredatına ve hiyerarşisine uygun olmalıdır.
  `;

  const prompt = `
    DERS: ${course}
    SINIF DÜZEYİ: ${grade}
    ZORLUK SEVİSESİ: ${difficulty}
    KAZANIM / ÖĞRENME ÇIKTISI: "${outcome}"
    İSTENEN SORU SAYISI: ${count}
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              text: { type: Type.STRING },
              expectedAnswer: { type: Type.STRING },
              keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
              maxScore: { type: Type.NUMBER },
              gradingSteps: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    text: { type: Type.STRING },
                    score: { type: Type.NUMBER }
                  },
                  required: ["text", "score"]
                }
              }
            },
            required: ["text", "expectedAnswer", "keywords", "maxScore", "gradingSteps"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Yapay zeka yanıt üretemedi (Boş yanıt).");

    return JSON.parse(text).map((q: any, i: number) => ({
      ...q,
      id: `gen-${Date.now()}-${i}`
    }));
  } catch (error: any) {
    console.error("Gemini Servis Hatası:", error);
    // Gerçek hata mesajını kullanıcıya ulaştır
    const detailedError = error.message?.includes("API_KEY_INVALID") 
