export default AnswerKeyUpload;

import React, { useState, useEffect } from 'react';
import { Exam, StudentSubmission, Question, UserSettings, PricingPlan, GradedExam } from './types';
import Header from './components/Header';
import Footer from './components/Footer';
import ExamSetup from './components/ExamSetup';
import UploadSection from './components/UploadSection';
import GradingDashboard from './components/GradingDashboard';
import GradingDetail from './components/GradingDetail';
import AnalyticsView from './components/AnalyticsView';
import QuestionPrep from './components/QuestionPrep';
import SettingsPanel from './components/SettingsPanel';
import ExamPaper from './components/ExamPaper';
import AboutView from './components/AboutView';
import HomePanel from './components/HomePanel';
import AdminPanel from './components/AdminPanel';
import PricingView from './components/PricingView';
import CheckoutView from './components/CheckoutView';
import ExamoraInfoView from './components/ExamoraInfoView';
import EduMetrikInfoView from './components/EduMetrikInfoView';
import PrivacyModal from './components/PrivacyModal';
import AnswerKeyUpload from './components/AnswerKeyUpload';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'home' | 'setup' | 'upload' | 'dashboard' | 'detail' | 'analytics' | 'question-prep' | 'settings' | 'exam-paper' | 'info' | 'admin' | 'admin-login' | 'pricing' | 'checkout' | 'examora-info' | 'edumetrik-info' | 'answer-key-upload'>('info');
  const [exam, setExam] = useState<Exam | null>(null);
  const [submissions, setSubmissions] = useState<StudentSubmission[]>([]);
  const [examHistory, setExamHistory] = useState<GradedExam[]>([]);
  const [selectedSubmissionId, setSelectedSubmissionId] = useState<string | null>(null);
  const [selectedPlan, setSelectedPlan] = useState<PricingPlan | null>(null);
  const [prefilledQuestions, setPrefilledQuestions] = useState<Question[]>([]);
  const [showPrivacy, setShowPrivacy] = useState(false);
  const [settings, setSettings] = useState<UserSettings>({
    teacherName: '',
    schoolName: '',
    subject: '',
    theme: 'light',
    aiSensitivity: 'normal',
    feedbackTone: 'encouraging',
    analyticsLevel: 'basic',
    savedClasses: []
  });

  const [adminPassword, setAdminPassword] = useState("");
  const [adminError, setAdminError] = useState(false);

  useEffect(() => {
    const savedExam = localStorage.getItem('notera_exam');
    const savedSubmissions = localStorage.getItem('notera_submissions');
    const savedSettings = localStorage.getItem('notera_settings');
    const savedHistory = localStorage.getItem('notera_history');
    const privacyAccepted = localStorage.getItem('notera_privacy_accepted');

    if (!privacyAccepted) setShowPrivacy(true);
    if (savedExam) setExam(JSON.parse(savedExam));
    if (savedSubmissions) setSubmissions(JSON.parse(savedSubmissions));
    if (savedHistory) setExamHistory(JSON.parse(savedHistory));
    if (savedSettings) {
      const parsedSettings = JSON.parse(savedSettings);
      setSettings({
        ...parsedSettings,
        analyticsLevel: parsedSettings.analyticsLevel || 'basic',
        savedClasses: parsedSettings.savedClasses || []
      });
      applyTheme(parsedSettings.theme);
    }

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.shiftKey && e.altKey && e.code === 'KeyA') {
        setCurrentView('admin-login');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handlePrivacyAccept = () => {
    localStorage.setItem('notera_privacy_accepted', 'true');
    setShowPrivacy(false);
  };

  const applyTheme = (theme: 'dark' | 'light' | 'system') => {
    const root = window.document.documentElement;
    if (theme === 'dark' || (theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  };

  const handleAdminAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === "admin123") {
      setCurrentView('admin');
      setAdminError(false);
      setAdminPassword("");
      window.scrollTo(0, 0);
    } else {
      setAdminError(true);
    }
  };

  const saveToLocal = (updatedExam: Exam | null, updatedSubmissions: StudentSubmission[], updatedHistory?: GradedExam[]) => {
    if (updatedExam) localStorage.setItem('notera_exam', JSON.stringify(updatedExam));
    else localStorage.removeItem('notera_exam');

    localStorage.setItem('notera_submissions', JSON.stringify(updatedSubmissions));
    if (updatedHistory) localStorage.setItem('notera_history', JSON.stringify(updatedHistory));
  };

  // KRİTİK: Yeni bir sınav akışı başladığında her şeyi sıfırla
  const startNewExamFlow = (targetView: typeof currentView) => {
    setExam(null);
    setSubmissions([]);
    setPrefilledQuestions([]);
    saveToLocal(null, []);
    setCurrentView(targetView);
  };

  const handleSettingsUpdate = (newSettings: UserSettings) => {
    setSettings(newSettings);
    localStorage.setItem('notera_settings', JSON.stringify(newSettings));
    applyTheme(newSettings.theme);
  };

  const handleExamSaved = (newExam: Exam) => {
    // Sınav değiştiyse (ID farklıysa) eski öğrenci kağıtlarını kesinlikle temizle
    if (!exam || exam.id !== newExam.id) {
      setSubmissions([]);
      saveToLocal(newExam, []);
    } else {
      saveToLocal(newExam, submissions);
    }
    setExam(newExam);
    setCurrentView('exam-paper');
  };

  const handleUploadComplete = (newSubmissions: StudentSubmission[]) => {
    const updated = [...submissions, ...newSubmissions];
    setSubmissions(updated);

    if (exam) {
      const avg = updated.reduce((a, b) => a + b.totalScore, 0) / (updated.length || 1);
      const gradedExam: GradedExam = {
        id: Date.now().toString(),
        exam: exam,
        submissions: updated,
        averageScore: Math.round(avg),
        createdAt: new Date().toISOString()
      };

      const newHistory = [gradedExam, ...examHistory];
      setExamHistory(newHistory);

      const newClasses = Array.from(new Set([...settings.savedClasses, exam.classSection]));
      const newSettings = { ...settings, savedClasses: newClasses };
      setSettings(newSettings);

      localStorage.setItem('notera_settings', JSON.stringify(newSettings));
      saveToLocal(exam, updated, newHistory);
    } else {
      saveToLocal(exam, updated, examHistory);
    }

    setCurrentView('dashboard');
  };

  const handleSubmissionUpdate = (updatedSub: StudentSubmission) => {
    const updated = submissions.map(s => s.id === updatedSub.id ? updatedSub : s);
    setSubmissions(updated);
    saveToLocal(exam, updated, examHistory);
  };

  const handleQuestionsGenerated = (questions: Question[]) => {
    setPrefilledQuestions(questions);
    setSubmissions([]); // Garanti temizlik
    saveToLocal(null, []);
    setCurrentView('setup');
  };

  const handleAnswerKeyParsed = (parsedData: Partial<Exam> & { questions: Question[] }, quickStart: boolean) => {
    setSubmissions([]); // Önceki kağıtları temizle

    const newExamId = `exam-${Date.now()}`;

    if (quickStart) {
      const newExam: Exam = {
        id: newExamId,
        type: 'open-ended',
        classSection: parsedData.classSection || 'Bilinmeyen Sınıf',
        courseName: parsedData.courseName || 'Genel Ders',
        examName: parsedData.examName || 'Yazılı Sınav',
        date: new Date().toISOString(),
        questions: parsedData.questions
      };
      setExam(newExam);
      saveToLocal(newExam, []);
      setCurrentView('upload');
    } else {
      setPrefilledQuestions(parsedData.questions);
      saveToLocal(null, []);
      setCurrentView('setup');
    }
  };

  const handlePlanSelection = (plan: PricingPlan) => {
    if (plan.price === 0) {
      setSettings({ ...settings, isPremium: false, analyticsLevel: 'basic' });
      setCurrentView('home');
    } else {
      setSelectedPlan(plan);
      setCurrentView('checkout');
    }
  };

  const handlePaymentSuccess = () => {
    if (selectedPlan) {
      const newSettings: UserSettings = {
        ...settings,
        isPremium: true,
        analyticsLevel: selectedPlan.analyticsLevel
      };
      setSettings(newSettings);
      localStorage.setItem('notera_settings', JSON.stringify(newSettings));
      setCurrentView('home');
    }
  };

  const renderView = () => {
    switch (currentView) {
      case 'info': return <AboutView onStart={() => setCurrentView('pricing')} />;
      case 'pricing': return <PricingView onSelectPlan={handlePlanSelection} />;
      case 'checkout': return selectedPlan ? <CheckoutView plan={selectedPlan} onCancel={() => setCurrentView('pricing')} onSuccess={handlePaymentSuccess} /> : null;
      case 'examora-info': return <ExamoraInfoView onStart={() => startNewExamFlow('question-prep')} />;
      case 'edumetrik-info': return <EduMetrikInfoView onStart={() => setCurrentView('dashboard')} isExamSet={!!exam} />;
      case 'home': return <HomePanel onNavigate={(view) => startNewExamFlow(view)} onResume={(view) => setCurrentView(view)} isExamSet={!!exam} hasSubmissions={submissions.length > 0} />;
      case 'answer-key-upload': return <AnswerKeyUpload onParsed={handleAnswerKeyParsed} onCancel={() => setCurrentView('home')} />;
      case 'settings': return <SettingsPanel settings={settings} onUpdate={handleSettingsUpdate} onResetAll={() => { localStorage.clear(); window.location.reload(); }} />;
      case 'question-prep': return <QuestionPrep onQuestionsGenerated={handleQuestionsGenerated} />;
      case 'setup': return <ExamSetup initialExam={exam} onSave={handleExamSaved} prefilledQuestions={prefilledQuestions} />;
      case 'exam-paper': return exam ? <ExamPaper exam={exam} settings={settings} onBack={() => setCurrentView('setup')} onStartGrading={() => setCurrentView('upload')} /> : null;
      case 'upload': return <UploadSection onUpload={handleUploadComplete} exam={exam!} settings={settings} />;
      case 'dashboard': return <GradingDashboard submissions={submissions} settings={settings} onSelect={(id) => { setSelectedSubmissionId(id); setCurrentView('detail'); }} onReset={() => { setSubmissions([]); saveToLocal(exam, [], examHistory); }} onViewAnalytics={() => setCurrentView('analytics')} />;
      case 'detail':
        const sub = submissions.find(s => s.id === selectedSubmissionId);
        return sub ? <GradingDetail submission={sub} exam={exam!} onBack={() => setCurrentView('dashboard')} onUpdate={handleSubmissionUpdate} /> : null;
      case 'analytics': return <AnalyticsView submissions={submissions} exam={exam!} settings={settings} onBack={() => setCurrentView('dashboard')} history={examHistory} />;
      case 'admin': return <AdminPanel />;
      case 'admin-login': return (
        <div className="min-h-[60vh] flex items-center justify-center animate-fade-in">
          <div className="bg-white dark:bg-slate-900 p-12 rounded-[3rem] border border-slate-200 dark:border-slate-800 shadow-2xl w-full max-w-md text-center">
            <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase mb-8">Admin Girişi</h2>
            <form onSubmit={handleAdminAuth} className="space-y-4">
              <input 
                type="password" 
                value={adminPassword}
                onChange={(e) => setAdminPassword(e.target.value)}
                placeholder="Şifre"
                className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border-2 rounded-2xl outline-none font-black text-center"
                autoFocus
              />
              <button type="submit" className="w-full py-5 bg-notera-purple text-white rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all">Giriş Yap</button>
              <button type="button" onClick={() => setCurrentView('home')} className="w-full text-slate-400 font-black text-[10px] uppercase tracking-widest">İptal</button>
            </form>
          </div>
        </div>
      );
      default: return <HomePanel onNavigate={(view) => startNewExamFlow(view)} onResume={(view) => setCurrentView(view)} isExamSet={!!exam} hasSubmissions={submissions.length > 0} />;
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-300 ${settings.theme === 'dark' ? 'bg-notera-dark text-slate-100' : 'bg-notera-gray text-slate-900'}`}>
      {showPrivacy && <PrivacyModal onAccept={handlePrivacyAccept} />}
      <Header currentView={currentView} onNavigate={(view) => setCurrentView(view)} isExamSet={!!exam} isPremium={settings.isPremium} />
      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        {renderView()}
      </main>
      <Footer onAdminClick={() => setCurrentView('admin-login')} onNavigate={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Exam, StudentSubmission, UserSettings } from './types';
import { gradeSubmission } from './services/geminiService';

interface UploadSectionProps {
  exam: Exam;
  onUpload: (submissions: StudentSubmission[]) => void;
  settings: UserSettings;
}

const UploadSection: React.FC<UploadSectionProps> = ({ exam, onUpload, settings }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [mode, setMode] = useState<'upload' | 'camera'>('upload');
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const startCamera = async () => {
    setMode('camera');
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      if (videoRef.current) videoRef.current.srcObject = stream;
    } catch (err) {
      alert("Kameraya erişilemedi.");
      setMode('upload');
    }
  };

  const captureAndGrade = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    const context = canvasRef.current.getContext('2d');
    if (!context) return;

    canvasRef.current.width = videoRef.current.videoWidth;
    canvasRef.current.height = videoRef.current.videoHeight;
    context.drawImage(videoRef.current, 0, 0);

    const base64 = canvasRef.current.toDataURL('image/jpeg');
    const fileName = `Kamera Tarama - ${new Date().toLocaleTimeString()}`;

    processFiles([{ data: base64, name: fileName }]);
  };

  const processFiles = async (fileDatas: { data: string, name: string }[]) => {
    setIsProcessing(true);
    const newSubmissions: StudentSubmission[] = [];

    for (let i = 0; i < fileDatas.length; i++) {
      setUploadProgress(Math.round(((i + 1) / fileDatas.length) * 100));
      const { data, name } = fileDatas[i];

      const sub: StudentSubmission = {
        id: `sub-${Date.now()}-${i}`,
        studentName: name.replace(/\.[^/.]+$/, ""),
        imageUrl: data,
        base64Data: data.split(',')[1],
        status: 'processing',
        results: [],
        totalScore: 0
      };

      try {
        const { results, totalScore } = await gradeSubmission(exam, sub, settings.feedbackTone);
        sub.results = results;
        sub.totalScore = totalScore;
        sub.status = 'graded';
      } catch (err) {
        console.error("Okuma hatası:", err);
        sub.status = 'pending';
      }
      newSubmissions.push(sub);
    }

    onUpload(newSubmissions);
    setIsProcessing(false);

    if (videoRef.current?.srcObject) {
      (videoRef.current.srcObject as MediaStream).getTracks().forEach(track => track.stop());
    }
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const fileList = Array.from(files);
    const fileDatas = await Promise.all(fileList.map(async (f: File) => ({
      data: await fileToBase64(f),
      name: f.name
    })));

    processFiles(fileDatas);
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  return (
    <div className="max-w-4xl mx-auto py-12 animate-fade-in">
      {/* ŞU ANKİ SINAV BİLGİSİ */}
      <div className="mb-10 p-8 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-[2.5rem] shadow-sm flex items-center justify-between">
        <div className="flex items-center gap-6">
          <div className="w-12 h-12 bg-notera-purple text-white rounded-2xl flex items-center justify-center text-xl">📄</div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Şu an okunan sınav:</p>
            <h3 className="text-xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">
              {exam.classSection} {exam.courseName} <span className="text-notera-turquoise ml-2">• {exam.examName}</span>
            </h3>
          </div>
        </div>
      </div>

      <div className="flex gap-4 mb-8 justify-center no-print">
        <button 
          onClick={() => setMode('upload')} 
          className={`px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${mode === 'upload' ? 'bg-notera-purple text-white shadow-lg' : 'bg-white dark:bg-slate-800 text-slate-400'}`}
        >
          DOSYA YÜKLE
        </button>
        <button 
          onClick={startCamera} 
          className={`px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${mode === 'camera' ? 'bg-notera-purple text-white shadow-lg' : 'bg-white dark:bg-slate-800 text-slate-400'}`}
        >
          KAMERA İLE TARA
        </button>
      </div>

      <div className={`relative border-4 border-dashed rounded-[3.5rem] p-12 transition-all min-h-[450px] flex items-center justify-center ${isProcessing ? 'bg-notera-purple/5 border-notera-purple' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800'}`}>
        {isProcessing ? (
          <div className="text-center space-y-8 animate-pulse">
            <div className="w-20 h-20 border-8 border-notera-turquoise border-t-transparent rounded-full animate-spin mx-auto"></div>
            <div className="space-y-2">
              <p className="text-notera-purple dark:text-notera-turquoise font-black text-3xl uppercase tracking-tighter">KAĞITLAR İŞLENİYOR</p>
              <p className="text-slate-400 font-bold text-lg">İlerleme: %{uploadProgress}</p>
            </div>
          </div>
        ) : mode === 'camera' ? (
          <div className="w-full max-w-lg space-y-8">
            <video ref={videoRef} autoPlay playsInline className="w-full rounded-[2.5rem] shadow-2xl bg-black border-4 border-notera-purple" />
            <canvas ref={canvasRef} className="hidden" />
            <button 
              onClick={captureAndGrade} 
              className="w-full py-8 bg-notera-turquoise text-white rounded-[2rem] font-black uppercase tracking-widest text-xl shadow-xl hover:scale-105 active:scale-95 transition-all"
            >
              ŞİMDİ TARA 📸
            </button>
          </div>
        ) : (
          <div className="text-center group cursor-pointer w-full">
            <input 
              type="file" 
              multiple 
              accept="image/*" 
              onChange={handleFileChange} 
              className="absolute inset-0 opacity-0 cursor-pointer z-10" 
            />
            <div className="space-y-6">
              <div className="w-24 h-24 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform">
                <svg className="w-12 h-12 text-slate-300 dark:text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                </svg>
              </div>
              <div className="space-y-2">
                <p className="text-2xl font-black text-slate-400 dark:text-slate-600 uppercase tracking-[0.2em]">ÖĞRENCİ KAĞITLARINI YÜKLE</p>
                <p className="text-sm font-bold text-slate-300 dark:text-slate-700">Dosyaları sürükleyin veya tıklayın.</p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default UploadSection;

import React, { useState, useEffect } from 'react';
import { Exam, StudentSubmission, Question, UserSettings, PricingPlan, GradedExam } from './types';
import Header from './components/Header';
import Footer from './components/Footer';
import ExamSetup from './components/ExamSetup';
import UploadSection from './components/UploadSection';
import GradingDashboard from './components/GradingDashboard';
import GradingDetail from './components/GradingDetail';
import AnalyticsView from './components/AnalyticsView';
import QuestionPrep from './components/QuestionPrep';
import SettingsPanel from './components/SettingsPanel';
import ExamPaper from './components/ExamPaper';
import AboutView from './components/AboutView';
import HomePanel from './components/HomePanel';
import AdminPanel from './components/AdminPanel';
import PricingView from './components/PricingView';
import CheckoutView from './components/CheckoutView';
import ExamoraInfoView from './components/ExamoraInfoView';
import EduMetrikInfoView from './components/EduMetrikInfoView';
import PrivacyModal from './components/PrivacyModal';
import AnswerKeyUpload from './components/AnswerKeyUpload';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'home' | 'setup' | 'upload' | 'dashboard' | 'detail' | 'analytics' | 'question-prep' | 'settings' | 'exam-paper' | 'info' | 'admin' | 'admin-login' | 'pricing' | 'checkout' | 'examora-info' | 'edumetrik-info' | 'answer-key-upload'>('info');
  const [exam, setExam] = useState<Exam | null>(null);
  const [submissions, setSubmissions] = useState<StudentSubmission[]>([]);
  const [examHistory, setExamHistory] = useState<GradedExam[]>([]);
  const [selectedSubmissionId, setSelectedSubmissionId] = useState<string | null>(null);
  const [selectedPlan, setSelectedPlan] = useState<PricingPlan | null>(null);
  const [prefilledQuestions, setPrefilledQuestions] = useState<Question[]>([]);
  const [showPrivacy, setShowPrivacy] = useState(false);
  const [settings, setSettings] = useState<UserSettings>({
    teacherName: '',
    schoolName: '',
    subject: '',
    theme: 'light',
    aiSensitivity: 'normal',
    feedbackTone: 'encouraging',
    analyticsLevel: 'basic',
    savedClasses: []
  });

  const [adminPassword, setAdminPassword] = useState("");
  const [adminError, setAdminError] = useState(false);

  useEffect(() => {
    const savedExam = localStorage.getItem('notera_exam');
    const savedSubmissions = localStorage.getItem('notera_submissions');
    const savedSettings = localStorage.getItem('notera_settings');
    const savedHistory = localStorage.getItem('notera_history');
    const privacyAccepted = localStorage.getItem('notera_privacy_accepted');

    if (!privacyAccepted) setShowPrivacy(true);
    if (savedExam) setExam(JSON.parse(savedExam));
    if (savedSubmissions) setSubmissions(JSON.parse(savedSubmissions));
    if (savedHistory) setExamHistory(JSON.parse(savedHistory));
    if (savedSettings) {
      const parsedSettings = JSON.parse(savedSettings);
      setSettings({
        ...parsedSettings,
        analyticsLevel: parsedSettings.analyticsLevel || 'basic',
        savedClasses: parsedSettings.savedClasses || []
      });
      applyTheme(parsedSettings.theme);
    }

    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.shiftKey && e.altKey && e.code === 'KeyA') {
        setCurrentView('admin-login');
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handlePrivacyAccept = () => {
    localStorage.setItem('notera_privacy_accepted', 'true');
    setShowPrivacy(false);
  };

  const applyTheme = (theme: 'dark' | 'light' | 'system') => {
    const root = window.document.documentElement;
    if (theme === 'dark' || (theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  };

  const handleAdminAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === "admin123") {
      setCurrentView('admin');
      setAdminError(false);
      setAdminPassword("");
      window.scrollTo(0, 0);
    } else {
      setAdminError(true);
    }
  };

  const saveToLocal = (updatedExam: Exam | null, updatedSubmissions: StudentSubmission[], updatedHistory?: GradedExam[]) => {
    if (updatedExam) localStorage.setItem('notera_exam', JSON.stringify(updatedExam));
    else localStorage.removeItem('notera_exam');

    localStorage.setItem('notera_submissions', JSON.stringify(updatedSubmissions));
    if (updatedHistory) localStorage.setItem('notera_history', JSON.stringify(updatedHistory));
  };

  // KRİTİK: Yeni bir sınav akışı başladığında her şeyi sıfırla
  const startNewExamFlow = (targetView: typeof currentView) => {
    setExam(null);
    setSubmissions([]);
    setPrefilledQuestions([]);
    saveToLocal(null, []);
    setCurrentView(targetView);
  };

  const handleSettingsUpdate = (newSettings: UserSettings) => {
    setSettings(newSettings);
    localStorage.setItem('notera_settings', JSON.stringify(newSettings));
    applyTheme(newSettings.theme);
  };

  const handleExamSaved = (newExam: Exam) => {
    if (!exam || exam.id !== newExam.id) {
      setSubmissions([]);
      saveToLocal(newExam, []);
    } else {
      saveToLocal(newExam, submissions);
    }
    setExam(newExam);
    setCurrentView('exam-paper');
  };

  const handleUploadComplete = (newSubmissions: StudentSubmission[]) => {
    const updated = [...submissions, ...newSubmissions];
    setSubmissions(updated);

    if (exam) {
      const avg = updated.reduce((a, b) => a + b.totalScore, 0) / (updated.length || 1);
      const gradedExam: GradedExam = {
        id: Date.now().toString(),
        exam: exam,
        submissions: updated,
        averageScore: Math.round(avg),
        createdAt: new Date().toISOString()
      };

      const newHistory = [gradedExam, ...examHistory];
      setExamHistory(newHistory);

      const newClasses = Array.from(new Set([...settings.savedClasses, exam.classSection]));
      const newSettings = { ...settings, savedClasses: newClasses };
      setSettings(newSettings);

      localStorage.setItem('notera_settings', JSON.stringify(newSettings));
      saveToLocal(exam, updated, newHistory);
    } else {
      saveToLocal(exam, updated, examHistory);
    }

    setCurrentView('dashboard');
  };

  const handleSubmissionUpdate = (updatedSub: StudentSubmission) => {
    const updated = submissions.map(s => s.id === updatedSub.id ? updatedSub : s);
    setSubmissions(updated);
    saveToLocal(exam, updated, examHistory);
  };

  const handleQuestionsGenerated = (questions: Question[]) => {
    setPrefilledQuestions(questions);
    setSubmissions([]); 
    saveToLocal(null, []);
    setCurrentView('setup');
  };

  const handleAnswerKeyParsed = (parsedData: Partial<Exam> & { questions: Question[] }, quickStart: boolean) => {
    setSubmissions([]); 

    const newExamId = `exam-${Date.now()}`;

    if (quickStart) {
      const newExam: Exam = {
        id: newExamId,
        type: 'open-ended',
        classSection: parsedData.classSection || 'Bilinmeyen Sınıf',
        courseName: parsedData.courseName || 'Genel Ders',
        examName: parsedData.examName || 'Yazılı Sınav',
        date: new Date().toISOString(),
        questions: parsedData.questions
      };
      setExam(newExam);
      saveToLocal(newExam, []);
      setCurrentView('upload');
    } else {
      setPrefilledQuestions(parsedData.questions);
      saveToLocal(null, []);
      setCurrentView('setup');
    }
  };

  const handlePlanSelection = (plan: PricingPlan) => {
    if (plan.price === 0) {
      setSettings({ ...settings, isPremium: false, analyticsLevel: 'basic' });
      setCurrentView('home');
    } else {
      setSelectedPlan(plan);
      setCurrentView('checkout');
    }
  };

  const handlePaymentSuccess = () => {
    if (selectedPlan) {
      const newSettings: UserSettings = {
        ...settings,
        isPremium: true,
        analyticsLevel: selectedPlan.analyticsLevel
      };
      setSettings(newSettings);
      localStorage.setItem('notera_settings', JSON.stringify(newSettings));
      setCurrentView('home');
    }
  };

  const renderView = () => {
    switch (currentView) {
      case 'info': return <AboutView onStart={() => setCurrentView('pricing')} />;
      case 'pricing': return <PricingView onSelectPlan={handlePlanSelection} />;
      case 'checkout': return selectedPlan ? <CheckoutView plan={selectedPlan} onCancel={() => setCurrentView('pricing')} onSuccess={handlePaymentSuccess} /> : null;
      case 'examora-info': return <ExamoraInfoView onStart={() => startNewExamFlow('question-prep')} />;
      case 'edumetrik-info': return <EduMetrikInfoView onStart={() => setCurrentView('dashboard')} isExamSet={!!exam} />;
      case 'home': return <HomePanel onNavigate={(view) => startNewExamFlow(view)} onResume={(view) => setCurrentView(view)} isExamSet={!!exam} hasSubmissions={submissions.length > 0} />;
      case 'answer-key-upload': return <AnswerKeyUpload onParsed={handleAnswerKeyParsed} onCancel={() => setCurrentView('home')} />;
      case 'settings': return <SettingsPanel settings={settings} onUpdate={handleSettingsUpdate} onResetAll={() => { localStorage.clear(); window.location.reload(); }} />;
      case 'question-prep': return <QuestionPrep onQuestionsGenerated={handleQuestionsGenerated} />;
      case 'setup': return <ExamSetup initialExam={exam} onSave={handleExamSaved} prefilledQuestions={prefilledQuestions} />;
      case 'exam-paper': return exam ? <ExamPaper exam={exam} settings={settings} onBack={() => setCurrentView('setup')} onStartGrading={() => setCurrentView('upload')} /> : null;
      case 'upload': return <UploadSection onUpload={handleUploadComplete} exam={exam!} settings={settings} />;
      case 'dashboard': return <GradingDashboard submissions={submissions} settings={settings} onSelect={(id) => { setSelectedSubmissionId(id); setCurrentView('detail'); }} onReset={() => { setSubmissions([]); saveToLocal(exam, [], examHistory); }} onViewAnalytics={() => setCurrentView('analytics')} />;
      case 'detail':
        const sub = submissions.find(s => s.id === selectedSubmissionId);
        return sub ? <GradingDetail submission={sub} exam={exam!} onBack={() => setCurrentView('dashboard')} onUpdate={handleSubmissionUpdate} /> : null;
      case 'analytics': return <AnalyticsView submissions={submissions} exam={exam!} settings={settings} onBack={() => setCurrentView('dashboard')} history={examHistory} />;
      case 'admin': return <AdminPanel />;
      case 'admin-login': return (
        <div className="min-h-[60vh] flex items-center justify-center animate-fade-in">
          <div className="bg-white dark:bg-slate-900 p-12 rounded-[3rem] border border-slate-200 dark:border-slate-800 shadow-2xl w-full max-w-md text-center">
            <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase mb-8">Admin Girişi</h2>
            <form onSubmit={handleAdminAuth} className="space-y-4">
              <input 
                type="password" 
                value={adminPassword}
                onChange={(e) => setAdminPassword(e.target.value)}
                placeholder="Şifre"
                className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border-2 rounded-2xl outline-none font-black text-center"
                autoFocus
              />
              <button type="submit" className="w-full py-5 bg-notera-purple text-white rounded-2xl font-black uppercase tracking-widest shadow-xl transition-all">Giriş Yap</button>
              <button type="button" onClick={() => setCurrentView('home')} className="w-full text-slate-400 font-black text-[10px] uppercase tracking-widest">İptal</button>
            </form>
          </div>
        </div>
      );
      default: return <HomePanel onNavigate={(view) => startNewExamFlow(view)} onResume={(view) => setCurrentView(view)} isExamSet={!!exam} hasSubmissions={submissions.length > 0} />;
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-300 ${settings.theme === 'dark' ? 'bg-notera-dark text-slate-100' : 'bg-notera-gray text-slate-900'}`}>
      {showPrivacy && <PrivacyModal onAccept={handlePrivacyAccept} />}
      <Header currentView={currentView} onNavigate={(view) => setCurrentView(view)} isExamSet={!!exam} isPremium={settings.isPremium} />
      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        {renderView()}
      </main>
      <Footer onAdminClick={() => setCurrentView('admin-login')} onNavigate={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { parseAnswerKey } from '../services/geminiService';
import { Question, Exam } from '../types';

interface AnswerKeyUploadProps {
  onParsed: (data: Partial<Exam> & { questions: Question[] }, quickStart: boolean) => void;
  onCancel: () => void;
}

const AnswerKeyUpload: React.FC<AnswerKeyUploadProps> = ({ onParsed, onCancel }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [parsedResult, setParsedResult] = useState<Partial<Exam> & { questions: Question[] } | null>(null);

  const [examName, setExamName] = useState('');
  const [courseName, setCourseName] = useState('');
  const [classSection, setClassSection] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setError(null);

    try {
      const base64 = await fileToBase64(file);
      const data = await parseAnswerKey(base64.split(',')[1]);
      setParsedResult(data);
      setExamName(data.examName || '1. Yazılı Sınav');
      setCourseName(data.courseName || '');
      setClassSection(''); 
    } catch (err: any) {
      setError(err.message || "Cevap anahtarı okunurken bir hata oluştu.");
    } finally {
      setIsProcessing(false);
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const handleConfirmAndStart = () => {
    if (!classSection.trim()) {
      alert("Lütfen bir sınıf (örn: 10-A) giriniz.");
      return;
    }
    if (!parsedResult) return;

    onParsed({
      ...parsedResult,
      examName,
      courseName,
      classSection
    }, true); 
  };

  const handleDetailedEdit = () => {
    if (!parsedResult) return;
    onParsed({
      ...parsedResult,
      examName,
      courseName,
      classSection
    }, false); 
  };

  const inputClasses = "w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border-2 border-transparent focus:border-notera-turquoise rounded-2xl outline-none transition-all font-bold text-lg text-slate-800 dark:text-white shadow-inner";
  const labelClasses = "block text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2 ml-2";

  if (parsedResult) {
    return (
      <div className="max-w-4xl mx-auto py-12 animate-fade-in space-y-8">
        <div className="bg-white dark:bg-slate-900 p-12 rounded-[3.5rem] shadow-2xl border border-notera-turquoise/30 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-12 opacity-5 pointer-events-none">
             <svg className="w-32 h-32" fill="currentColor" viewBox="0 0 24 24"><path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z"/></svg>
          </div>

          <div className="flex items-center gap-6 mb-10">
            <div className="w-16 h-16 bg-notera-turquoise text-white rounded-2xl flex items-center justify-center text-3xl shadow-lg shadow-notera-turquoise/20">✓</div>
            <div>
              <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Sınav Yapısı Oluşturuldu</h2>
              <p className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">AI {parsedResult.questions.length} adet soru ve puanlama kuralı tespit etti.</p>
            </div>
          </div>

          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className={labelClasses}>Sınav Başlığı</label>
                <input 
                  type="text" 
                  value={examName} 
                  onChange={(e) => setExamName(e.target.value)}
                  placeholder="Örn: 1. Dönem 1. Yazılı" 
                  className={inputClasses} 
                />
              </div>
              <div>
                <label className={labelClasses}>Ders Adı</label>
                <input 
                  type="text" 
                  value={courseName} 
                  onChange={(e) => setCourseName(e.target.value)}
                  placeholder="Örn: Biyoloji" 
                  className={inputClasses} 
                />
              </div>
            </div>

            <div>
              <label className={labelClasses}>Hangi Sınıf? (Girilmesi Zorunlu)</label>
              <input 
                type="text" 
                value={classSection} 
                onChange={(e) => setClassSection(e.target.value)}
                placeholder="Örn: 9-C" 
                className={`${inputClasses} border-notera-purple/20 ring-4 ring-notera-purple/5`}
                autoFocus
              />
            </div>

            <div className="pt-6 flex flex-col sm:flex-row gap-4">
              <button 
                onClick={handleConfirmAndStart}
                className="flex-[2] py-6 bg-notera-purple text-white rounded-[2rem] font-black text-sm tracking-widest uppercase shadow-xl hover:bg-notera-dark transition-all flex items-center justify-center gap-3"
              >
                ONAYLA VE OKUMAYA BAŞLA
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg>
              </button>
              <button 
                onClick={handleDetailedEdit}
                className="flex-1 py-6 bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400 rounded-[2rem] font-black text-[10px] uppercase tracking-widest hover:bg-slate-200 transition-all border-2 border-transparent"
              >
                DETAYLI DÜZENLE
              </button>
            </div>
          </div>
        </div>

        <div className="bg-slate-50 dark:bg-slate-800/30 p-10 rounded-[2.5rem] border border-dashed border-slate-200 dark:border-slate-800">
           <h3 className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-6">AI Tespit Özeti</h3>
           <div className="space-y-4">
              {parsedResult.questions.map((q, i) => (
                <div key={i} className="flex justify-between items-center p-4 bg-white dark:bg-slate-900/50 rounded-xl shadow-sm">
                   <div className="flex items-center gap-4">
                     <span className="w-8 h-8 bg-notera-purple/10 text-notera-purple rounded-lg flex items-center justify-center font-black text-xs">{i+1}</span>
                     <span className="text-sm font-bold text-slate-600 dark:text-slate-300 truncate max-w-[400px]">{q.text}</span>
                   </div>
                   <span className="shrink-0 font-black text-notera-turquoise text-xs">{q.maxScore} PUAN</span>
                </div>
              ))}
           </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto py-12 animate-fade-in space-y-12">
      <div className="bg-notera-purple p-12 rounded-[4rem] text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-12 opacity-10 rotate-12 pointer-events-none">
           <svg className="w-64 h-64" fill="currentColor" viewBox="0 0 24 24"><path d="M15.5 14h-.79l-.28-.27A6.471 6.471 0 0016 9.5 6.5 6.5 0 109.5 16c1.61 0 3.09-.59 4.23-1.57l.27.28v.79l5 4.99L20.49 19l-4.99-5zm-6 0C7.01 14 5 11.99 5 9.5S7.01 5 9.5 5 14 7.01 14 9.5 11.99 14 9.5 14z" /></svg>
        </div>
        <div className="relative z-10 space-y-4">
          <h2 className="text-4xl md:text-5xl font-black uppercase tracking-tighter leading-none">Cevap Anahtarını <br/> <span className="text-notera-turquoise italic">Sisteme Tanıt</span></h2>
          <p className="text-xl text-slate-200 font-medium max-w-xl">Cevap anahtarının veya senin çözdüğün örnek bir kağıdın fotoğrafını çek; biz her şeyi otomatik çıkaralım.</p>
        </div>
      </div>

      <div className={`relative border-8 border-dashed rounded-[4rem] p-16 transition-all min-h-[450px] flex items-center justify-center ${isProcessing ? 'bg-notera-purple/5 border-notera-purple' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800'}`}>
        {isProcessing ? (
          <div className="text-center space-y-8 animate-pulse">
            <div className="w-24 h-24 border-8 border-notera-turquoise border-t-transparent rounded-full animate-spin mx-auto"></div>
            <div className="space-y-2">
              <p className="text-notera-purple dark:text-notera-turquoise font-black text-3xl uppercase tracking-tighter">ANAHTAR ÇÖZÜMLENİYOR</p>
              <p className="text-slate-400 font-bold">Lütfen bekleyin, sorular ayrıştırılıyor...</p>
            </div>
          </div>
        ) : (
          <div className="text-center group cursor-pointer w-full">
            <input 
              ref={fileInputRef}
              type="file" 
              accept="image/*" 
              onChange={handleUpload} 
              className="absolute inset-0 opacity-0 cursor-pointer z-10" 
            />
            {error && (
              <div className="mb-8 p-6 bg-rose-50 text-rose-600 rounded-[2rem] border-2 border-rose-100 font-black uppercase text-xs tracking-widest animate-shake">
                ⚠️ {error}
              </div>
            )}
            <div className="space-y-8">
              <div className="w-32 h-32 bg-slate-50 dark:bg-slate-800 rounded-[2.5rem] flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform shadow-inner border-2 border-transparent group-hover:border-notera-purple/20">
                <svg className="w-16 h-16 text-notera-purple" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                </svg>
              </div>
              <div className="space-y-4">
                <p className="text-3xl font-black text-slate-800 dark:text-white uppercase tracking-tighter">FOTOĞRAFI YÜKLE VEYA ÇEK</p>
                <p className="text-slate-400 font-bold text-lg max-w-md mx-auto italic">Cevap anahtarının net bir fotoğrafını yüklemen yeterli.</p>
              </div>
              <button className="px-12 py-5 bg-notera-purple text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-2xl group-hover:bg-notera-turquoise transition-colors">YÜKLEMEK İÇİN TIKLA</button>
            </div>
          </div>
        )}
      </div>

      <div className="flex justify-center">
        <button onClick={onCancel} className="text-slate-400 font-black text-xs uppercase tracking-[0.4em] hover:text-rose-500 transition-colors">İşlemi İptal Et</button>
      </div>
    </div>
  );
};

export default AnswerKeyUpload;

import React, { useState, useEffect } from 'react';
import { Exam, StudentSubmission, Question, UserSettings, PricingPlan, GradedExam } from './types';
import Header from './components/Header';
import Footer from './components/Footer';
import ExamSetup from './components/ExamSetup';
import UploadSection from './components/UploadSection';
import GradingDashboard from './components/GradingDashboard';
import GradingDetail from './components/GradingDetail';
import AnalyticsView from './components/AnalyticsView';
import QuestionPrep from './components/QuestionPrep';
import SettingsPanel from './components/SettingsPanel';
import ExamPaper from './components/ExamPaper';
import AboutView from './components/AboutView';
import HomePanel from './components/HomePanel';
import AdminPanel from './components/AdminPanel';
import PricingView from './components/PricingView';
import CheckoutView from './components/CheckoutView';
import ExamoraInfoView from './components/ExamoraInfoView';
import EduMetrikInfoView from './components/EduMetrikInfoView';
import PrivacyModal from './components/PrivacyModal';
import AnswerKeyUpload from './components/AnswerKeyUpload';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<'home' | 'setup' | 'upload' | 'dashboard' | 'detail' | 'analytics' | 'question-prep' | 'settings' | 'exam-paper' | 'info' | 'admin' | 'admin-login' | 'pricing' | 'checkout' | 'examora-info' | 'edumetrik-info' | 'answer-key-upload'>('info');
  const [exam, setExam] = useState<Exam | null>(null);
  const [submissions, setSubmissions] = useState<StudentSubmission[]>([]);
  const [examHistory, setExamHistory] = useState<GradedExam[]>([]);
  const [selectedSubmissionId, setSelectedSubmissionId] = useState<string | null>(null);
  const [selectedPlan, setSelectedPlan] = useState<PricingPlan | null>(null);
  const [prefilledQuestions, setPrefilledQuestions] = useState<Question[]>([]);
  const [showPrivacy, setShowPrivacy] = useState(false);
  const [settings, setSettings] = useState<UserSettings>({
    teacherName: '',
    schoolName: '',
    subject: '',
    theme: 'light',
    aiSensitivity: 'normal',
    feedbackTone: 'encouraging',
    analyticsLevel: 'basic',
    savedClasses: []
  });

  const [adminPassword, setAdminPassword] = useState("");

  useEffect(() => {
    const savedExam = localStorage.getItem('notera_active_exam');
    const savedSubmissions = localStorage.getItem('notera_active_submissions');
    const savedSettings = localStorage.getItem('notera_settings');
    const savedHistory = localStorage.getItem('notera_history');
    const privacyAccepted = localStorage.getItem('notera_privacy_accepted');

    if (!privacyAccepted) setShowPrivacy(true);
    if (savedExam) setExam(JSON.parse(savedExam));
    if (savedSubmissions) setSubmissions(JSON.parse(savedSubmissions));
    if (savedHistory) setExamHistory(JSON.parse(savedHistory));
    if (savedSettings) {
      const parsed = JSON.parse(savedSettings);
      setSettings(parsed);
      applyTheme(parsed.theme);
    }
  }, []);

  const applyTheme = (theme: 'dark' | 'light' | 'system') => {
    const root = window.document.documentElement;
    if (theme === 'dark' || (theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  };

  const saveToLocal = (updatedExam: Exam | null, updatedSubmissions: StudentSubmission[], updatedHistory?: GradedExam[]) => {
    if (updatedExam) localStorage.setItem('notera_active_exam', JSON.stringify(updatedExam));
    else localStorage.removeItem('notera_active_exam');

    localStorage.setItem('notera_active_submissions', JSON.stringify(updatedSubmissions));
    if (updatedHistory) localStorage.setItem('notera_history', JSON.stringify(updatedHistory));
  };

  // KRİTİK: Yeni sınav akışını başlatırken hafızayı tam temizle
  const startNewExamFlow = (targetView: typeof currentView) => {
    localStorage.removeItem('notera_active_exam');
    localStorage.removeItem('notera_active_submissions');
    setExam(null);
    setSubmissions([]);
    setPrefilledQuestions([]);
    setCurrentView(targetView);
  };

  const handleExamSaved = (newExam: Exam) => {
    setExam(newExam);
    setSubmissions([]); // Sınav kaydedildiğinde eski kağıtları sil
    saveToLocal(newExam, []);
    setCurrentView('exam-paper');
  };

  const handleAnswerKeyParsed = (parsedData: Partial<Exam> & { questions: Question[] }, quickStart: boolean) => {
    // Session bazlı yeni ID oluştur
    const newExamId = `exam-${Date.now()}`;

    if (quickStart) {
      const newExam: Exam = {
        id: newExamId,
        type: 'open-ended',
        classSection: parsedData.classSection || 'Bilinmeyen Sınıf',
        courseName: parsedData.courseName || 'Ders Belirtilmedi',
        examName: parsedData.examName || 'Yeni Yazılı',
        date: new Date().toISOString(),
        questions: parsedData.questions
      };
      setExam(newExam);
      setSubmissions([]); // Kesin temizlik
      saveToLocal(newExam, []);
      setCurrentView('upload');
    } else {
      setPrefilledQuestions(parsedData.questions);
      setExam(null);
      setSubmissions([]);
      saveToLocal(null, []);
      setCurrentView('setup');
    }
  };

  const handleUploadComplete = (newSubmissions: StudentSubmission[]) => {
    const updated = [...submissions, ...newSubmissions];
    setSubmissions(updated);

    if (exam) {
      const avg = updated.reduce((a, b) => a + b.totalScore, 0) / (updated.length || 1);
      const gradedExam: GradedExam = {
        id: Date.now().toString(),
        exam: exam,
        submissions: updated,
        averageScore: Math.round(avg),
        createdAt: new Date().toISOString()
      };

      const newHistory = [gradedExam, ...examHistory];
      setExamHistory(newHistory);
      saveToLocal(exam, updated, newHistory);
    }
    setCurrentView('dashboard');
  };

  const renderView = () => {
    switch (currentView) {
      case 'info': return <AboutView onStart={() => setCurrentView('pricing')} />;
      case 'pricing': return <PricingView onSelectPlan={(p) => { if(p.price === 0) setCurrentView('home'); else { setSelectedPlan(p); setCurrentView('checkout'); }}} />;
      case 'checkout': return <CheckoutView plan={selectedPlan!} onCancel={() => setCurrentView('pricing')} onSuccess={() => setCurrentView('home')} />;
      case 'home': return <HomePanel onNavigate={startNewExamFlow} onResume={(v) => setCurrentView(v)} isExamSet={!!exam} hasSubmissions={submissions.length > 0} />;
      case 'answer-key-upload': return <AnswerKeyUpload onParsed={handleAnswerKeyParsed} onCancel={() => setCurrentView('home')} />;
      case 'setup': return <ExamSetup initialExam={exam} onSave={handleExamSaved} prefilledQuestions={prefilledQuestions} />;
      case 'upload': return <UploadSection exam={exam!} onUpload={handleUploadComplete} settings={settings} />;
      case 'dashboard': return <GradingDashboard submissions={submissions} settings={settings} onSelect={(id) => { setSelectedSubmissionId(id); setCurrentView('detail'); }} onReset={() => { setSubmissions([]); saveToLocal(exam, []); }} onViewAnalytics={() => setCurrentView('analytics')} />;
      case 'detail':
        const sub = submissions.find(s => s.id === selectedSubmissionId);
        return sub ? <GradingDetail submission={sub} exam={exam!} onBack={() => setCurrentView('dashboard')} onUpdate={(u) => { const updated = submissions.map(s => s.id === u.id ? u : s); setSubmissions(updated); saveToLocal(exam, updated); }} /> : null;
      case 'analytics': return <AnalyticsView submissions={submissions} exam={exam!} settings={settings} onBack={() => setCurrentView('dashboard')} history={examHistory} />;
      case 'question-prep': return <QuestionPrep onQuestionsGenerated={(q) => { setPrefilledQuestions(q); setCurrentView('setup'); }} />;
      case 'settings': return <SettingsPanel settings={settings} onUpdate={(s) => { setSettings(s); applyTheme(s.theme); localStorage.setItem('notera_settings', JSON.stringify(s)); }} onResetAll={() => { localStorage.clear(); window.location.reload(); }} />;
      case 'exam-paper': return <ExamPaper exam={exam!} settings={settings} onBack={() => setCurrentView('setup')} onStartGrading={() => setCurrentView('upload')} />;
      case 'admin-login': return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-6">
          <input type="password" value={adminPassword} onChange={(e) => setAdminPassword(e.target.value)} placeholder="Admin Şifresi" className="px-6 py-4 rounded-2xl bg-white dark:bg-slate-800 border-2" />
          <button onClick={() => { if(adminPassword === "admin123") setCurrentView('admin'); }} className="px-12 py-4 bg-notera-purple text-white rounded-2xl font-black">Giriş</button>
        </div>
      );
      case 'admin': return <AdminPanel />;
      default: return <HomePanel onNavigate={startNewExamFlow} onResume={(v) => setCurrentView(v)} isExamSet={!!exam} hasSubmissions={submissions.length > 0} />;
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-300 ${settings.theme === 'dark' ? 'bg-notera-dark text-slate-100' : 'bg-notera-gray text-slate-900'}`}>
      {showPrivacy && <PrivacyModal onAccept={() => { setShowPrivacy(false); localStorage.setItem('notera_privacy_accepted', 'true'); }} />}
      <Header currentView={currentView} onNavigate={(v) => setCurrentView(v)} isExamSet={!!exam} isPremium={settings.isPremium} />
      <main className="flex-grow container mx-auto px-4 py-8 max-w-6xl">
        {renderView()}
      </main>
      <Footer onAdminClick={() => setCurrentView('admin-login')} onNavigate={setCurrentView} />
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { parseAnswerKey } from '../services/geminiService';
import { Question, Exam } from '../types';

interface AnswerKeyUploadProps {
  onParsed: (data: Partial<Exam> & { questions: Question[] }, quickStart: boolean) => void;
  onCancel: () => void;
}

const AnswerKeyUpload: React.FC<AnswerKeyUploadProps> = ({ onParsed, onCancel }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [parsedResult, setParsedResult] = useState<Partial<Exam> & { questions: Question[] } | null>(null);

  const [examName, setExamName] = useState('');
  const [courseName, setCourseName] = useState('');
  const [classSection, setClassSection] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setError(null);

    try {
      const base64 = await fileToBase64(file);
      const data = await parseAnswerKey(base64.split(',')[1]);
      setParsedResult(data);
      setExamName(data.examName || '1. Yazılı Sınav');
      setCourseName(data.courseName || 'Genel Ders');
      setClassSection(''); 
    } catch (err: any) {
      setError(err.message || "Cevap anahtarı okunamadı. Lütfen görselin net olduğundan emin olun.");
    } finally {
      setIsProcessing(false);
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const handleConfirmAndStart = () => {
    if (!classSection.trim()) {
      alert("Lütfen sınavı yapacağınız sınıfı (örn: 10-A) giriniz.");
      return;
    }
    if (!parsedResult) return;

    onParsed({
      ...parsedResult,
      examName,
      courseName,
      classSection
    }, true); 
  };

  const handleDetailedEdit = () => {
    if (!parsedResult) return;
    onParsed({
      ...parsedResult,
      examName,
      courseName,
      classSection
    }, false); 
  };

  const inputClasses = "w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border-2 border-transparent focus:border-notera-turquoise rounded-2xl outline-none transition-all font-bold text-lg text-slate-800 dark:text-white shadow-inner";
  const labelClasses = "block text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-2 ml-2";

  if (parsedResult) {
    return (
      <div className="max-w-4xl mx-auto py-12 animate-fade-in space-y-8">
        <div className="bg-white dark:bg-slate-900 p-12 rounded-[3.5rem] shadow-2xl border border-notera-turquoise/30 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-12 opacity-5 pointer-events-none">
             <svg className="w-32 h-32" fill="currentColor" viewBox="0 0 24 24"><path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z"/></svg>
          </div>

          <div className="flex items-center gap-6 mb-10">
            <div className="w-16 h-16 bg-notera-turquoise text-white rounded-2xl flex items-center justify-center text-3xl shadow-lg shadow-notera-turquoise/20">✓</div>
            <div>
              <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tighter">Cevap Anahtarı Hazır</h2>
              <p className="text-slate-500 font-bold uppercase text-[10px] tracking-widest">AI {parsedResult.questions.length} adet soru tespit etti.</p>
            </div>
          </div>

          <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className={labelClasses}>Sınav Başlığı</label>
                <input 
                  type="text" 
                  value={examName} 
                  onChange={(e) => setExamName(e.target.value)}
                  placeholder="Örn: 1. Dönem 1. Yazılı" 
                  className={inputClasses} 
                />
              </div>
              <div>
                <label className={labelClasses}>Ders Adı</label>
                <input 
                  type="text" 
                  value={courseName} 
                  onChange={(e) => setCourseName(e.target.value)}
                  placeholder="Örn: Biyoloji" 
                  className={inputClasses} 
                />
              </div>
            </div>

            <div>
              <label className={labelClasses}>Hedef Sınıf / Şube (Örn: 9-B)</label>
              <input 
                type="text" 
                value={classSection} 
                onChange={(e) => setClassSection(e.target.value)}
                placeholder="Bu sınav hangi sınıf için?" 
